// ── INTERP: interpretation per [lord][house] ───────────────────────────────
// Filled per lord. Each entry: { ta, te, bn, mr, pa, gu }.
const INTERP = {
  1: {
    1:{ta:'லக்னாதிபதி முதலாம் பாவத்தில் இருந்தால் ஜாதகர் தன்னம்பிக்கை, உடல் வலிமை, தன்னம்பிக்கையுள்ள மற்றும் சக்திவாய்ந்த ஆளுமை உடையவராகிறார். நல்ல ஆரோக்கியமும் கட்டளையிடும் தோற்றமும் அருளப்படுகின்றன.',te:'లగ్నాధిపతి మొదటి భావంలో ఉంటే జాతకుడు స్వావలంబన, శారీరక బలం, ఆత్మవిశ్వాసం మరియు శక్తివంతమైన వ్యక్తిత్వం కలిగి ఉంటాడు. మంచి ఆరోగ్యం మరియు ఆజ్ఞాపించే ఉనికి లభిస్తాయి.',bn:'লগ্নেশ প্রথম ভাবে থাকলে জাতক আত্মনির্ভর, দৈহিকভাবে শক্তিশালী, আত্মবিশ্বাসী ও শক্তিশালী ব্যক্তিত্বসম্পন্ন হয়। উত্তম স্বাস্থ্য ও প্রভাবশালী উপস্থিতি লাভ করে।',mr:'लग्नेश पहिल्या भावात असल्यास जातक आत्मनिर्भर, शारीरिकदृष्ट्या बलवान, आत्मविश्वासी व शक्तिशाली व्यक्तिमत्त्वाचा होतो. उत्तम आरोग्य व प्रभावी उपस्थिती लाभते.',pa:'ਲਗਨੇਸ਼ ਪਹਿਲੇ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਜਾਤਕ ਆਤਮ-ਨਿਰਭਰ, ਸਰੀਰਕ ਤੌਰ ਤੇ ਬਲਵਾਨ, ਆਤਮ-ਵਿਸ਼ਵਾਸੀ ਅਤੇ ਸ਼ਕਤੀਸ਼ਾਲੀ ਸ਼ਖਸੀਅਤ ਵਾਲਾ ਹੁੰਦਾ ਹੈ। ਚੰਗੀ ਸਿਹਤ ਅਤੇ ਹੁਕਮ ਦੇਣ ਵਾਲੀ ਮੌਜੂਦਗੀ ਮਿਲਦੀ ਹੈ।',gu:'લગ્નેશ પ્રથમ ભાવમાં હોય તો જાતક આત્મનિર્ભર, શારીરિક રીતે બળવાન, આત્મવિશ્વાસી અને શક્તિશાળી વ્યક્તિત્વ ધરાવતો હોય છે. ઉત્તમ આરોગ્ય અને આજ્ઞા આપતી હાજરી મળે છે.'},
    2:{ta:'லக்னாதிபதி இரண்டாம் பாவத்தில் இருந்தால் நிதி வளம், உணவு மற்றும் குடும்பப் பற்று, நல்ல பேச்சு மற்றும் செல்வ சேமிப்பை அளிக்கிறது. ஜாதகரின் அடையாளம் பொருள் பாதுகாப்புடன் வலுவாக இணைந்துள்ளது.',te:'లగ్నాధిపతి రెండవ భావంలో ఉంటే ఆర్థిక సమృద్ధి, ఆహారం మరియు కుటుంబ ప్రేమ, మంచి మాట మరియు సంపద సంచయాన్ని ఇస్తుంది. జాతకుని గుర్తింపు భౌతిక భద్రతతో బలంగా ముడిపడి ఉంటుంది.',bn:'লগ্নেশ দ্বিতীয় ভাবে থাকলে আর্থিক সমৃদ্ধি, খাদ্য ও পরিবারের প্রতি প্রেম, ভালো বাক্য ও সম্পদ সঞ্চয় দেয়। জাতকের পরিচয় বস্তুগত নিরাপত্তার সাথে দৃঢ়ভাবে যুক্ত।',mr:'लग्नेश दुसऱ्या भावात असल्यास आर्थिक समृद्धी, अन्न व कुटुंबप्रेम, चांगली वाणी व संपत्ती संचय देते. जातकाची ओळख भौतिक सुरक्षेशी दृढपणे जोडलेली असते.',pa:'ਲਗਨੇਸ਼ ਦੂਜੇ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਵਿੱਤੀ ਖੁਸ਼ਹਾਲੀ, ਭੋਜਨ ਅਤੇ ਪਰਿਵਾਰ ਪ੍ਰੇਮ, ਚੰਗੀ ਬੋਲੀ ਅਤੇ ਦੌਲਤ ਸੰਚਯ ਦਿੰਦਾ ਹੈ। ਜਾਤਕ ਦੀ ਪਛਾਣ ਪਦਾਰਥਕ ਸੁਰੱਖਿਆ ਨਾਲ ਮਜ਼ਬੂਤੀ ਨਾਲ ਜੁੜੀ ਹੁੰਦੀ ਹੈ।',gu:'લગ્નેશ બીજા ભાવમાં હોય તો આર્થિક સમૃદ્ધિ, ખોરાક અને કુટુંબપ્રેમ, સારી વાણી અને સંપત્તિ સંચય આપે છે. જાતકની ઓળખ ભૌતિક સુરક્ષા સાથે દૃઢપણે જોડાયેલી હોય છે.'},
    3:{ta:'லக்னாதிபதி மூன்றாம் பாவத்தில் இருந்தால் ஜாதகர் தைரியசாலி, தொடர்பில் திறமையான, எழுத்து அல்லது ஊடகத்தில் திறமையான மற்றும் உடன்பிறந்தோருக்கு நெருக்கமானவராகிறார். குறுகிய பயணங்கள் மற்றும் சுய-வெளிப்பாட்டில் தீவிர ஆர்வம் உண்டு.',te:'లగ్నాధిపతి మూడవ భావంలో ఉంటే జాతకుడు ధైర్యవంతుడు, సంభాషణలో నేర్పరి, రచన లేదా మీడియాలో నైపుణ్యం కలిగి, సహోదరులకు దగ్గరగా ఉంటాడు. చిన్న ప్రయాణాలు మరియు స్వీయ-వ్యక్తీకరణలో తీవ్ర ఆసక్తి ఉంటుంది.',bn:'লগ্নেশ তৃতীয় ভাবে থাকলে জাতক সাহসী, যোগাযোগে দক্ষ, লেখা বা মিডিয়ায় দক্ষ এবং ভাইবোনের ঘনিষ্ঠ হয়। স্বল্প ভ্রমণ ও আত্মপ্রকাশে গভীর আগ্রহ থাকে।',mr:'लग्नेश तिसऱ्या भावात असल्यास जातक धाडसी, संवादात कुशल, लेखन किंवा माध्यमात निपुण व भावंडांच्या जवळचा होतो. लहान प्रवास व आत्म-अभिव्यक्तीत तीव्र रुची असते.',pa:'ਲਗਨੇਸ਼ ਤੀਜੇ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਜਾਤਕ ਬਹਾਦਰ, ਸੰਚਾਰ ਵਿੱਚ ਨਿਪੁੰਨ, ਲਿਖਤ ਜਾਂ ਮੀਡੀਆ ਵਿੱਚ ਹੁਨਰਮੰਦ ਅਤੇ ਭੈਣ-ਭਰਾਵਾਂ ਦੇ ਨੇੜੇ ਹੁੰਦਾ ਹੈ। ਛੋਟੇ ਸਫ਼ਰਾਂ ਅਤੇ ਸਵੈ-ਪ੍ਰਗਟਾਵੇ ਵਿੱਚ ਡੂੰਘੀ ਰੁਚੀ ਹੁੰਦੀ ਹੈ।',gu:'લગ્નેશ ત્રીજા ભાવમાં હોય તો જાતક હિંમતવાન, સંવાદમાં કુશળ, લેખન કે મીડિયામાં નિપુણ અને ભાઈ-બહેનની નજીક હોય છે. ટૂંકી મુસાફરી અને સ્વ-અભિવ્યક્તિમાં ઊંડો રસ હોય છે.'},
    4:{ta:'லக்னாதிபதி நான்காம் பாவத்தில் இருந்தால் வீட்டு மகிழ்ச்சி, நல்ல தாய், நில சொத்து, வாகனங்கள் மற்றும் அக அமைதியை அளிக்கிறது. ஜாதகர் வீடு மற்றும் தாய்நாட்டில் அடையாளத்தைக் காண்கிறார்.',te:'లగ్నాధిపతి నాల్గవ భావంలో ఉంటే గృహ సౌఖ్యం, మంచి తల్లి, భూమి ఆస్తి, వాహనాలు మరియు అంతర్ శాంతిని ప్రసాదిస్తుంది. జాతకుడు ఇల్లు మరియు మాతృభూమిలో గుర్తింపును పొందుతాడు.',bn:'লগ্নেশ চতুর্থ ভাবে থাকলে গৃহসুখ, ভালো মাতা, জমি-সম্পত্তি, যানবাহন ও অন্তঃশান্তি দেয়। জাতক বাড়ি ও মাতৃভূমিতে পরিচয় খুঁজে পায়।',mr:'लग्नेश चौथ्या भावात असल्यास गृहसुख, चांगली माता, जमीन-मालमत्ता, वाहने व अंतर्शांती देते. जातक घर व मातृभूमीत ओळख शोधतो.',pa:'ਲਗਨੇਸ਼ ਚੌਥੇ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਘਰੇਲੂ ਖੁਸ਼ੀ, ਚੰਗੀ ਮਾਂ, ਜ਼ਮੀਨ-ਜਾਇਦਾਦ, ਵਾਹਨ ਅਤੇ ਅੰਦਰੂਨੀ ਸ਼ਾਂਤੀ ਦਿੰਦਾ ਹੈ। ਜਾਤਕ ਘਰ ਅਤੇ ਮਾਤਭੂਮੀ ਵਿੱਚ ਪਛਾਣ ਲੱਭਦਾ ਹੈ।',gu:'લગ્નેશ ચોથા ભાવમાં હોય તો ગૃહસુખ, સારી માતા, જમીન-મિલકત, વાહનો અને આંતરિક શાંતિ આપે છે. જાતક ઘર અને માતૃભૂમિમાં ઓળખ મેળવે છે.'},
    5:{ta:'லக்னாதிபதி ஐந்தாம் பாவத்தில் இருந்தால் புத்தி, படைப்பாற்றல், உயர் கல்வி, குழந்தைகள், காதல் விவகாரங்கள் மற்றும் ஆன்மிக நாட்டத்தை அளிக்கிறது. ஜாதகர் கலைத்திறன் மற்றும் கல்வி நாட்டம் கொண்டவராகிறார்.',te:'లగ్నాధిపతి ఐదవ భావంలో ఉంటే బుద్ధి, సృజనాత్మకత, ఉన్నత విద్య, పిల్లలు, ప్రేమ వ్యవహారాలు మరియు ఆధ్యాత్మిక ప్రవృత్తిని ఇస్తుంది. జాతకుడు కళాత్మకుడు మరియు విద్యా ప్రవృత్తి కలిగి ఉంటాడు.',bn:'লগ্নেশ পঞ্চম ভাবে থাকলে বুদ্ধি, সৃজনশীলতা, উচ্চশিক্ষা, সন্তান, প্রেম ও আধ্যাত্মিক প্রবণতা দেয়। জাতক শৈল্পিক ও একাডেমিকভাবে প্রতিভাবান হয়।',mr:'लग्नेश पाचव्या भावात असल्यास बुद्धी, सर्जनशीलता, उच्च शिक्षण, संतती, प्रेम व आध्यात्मिक प्रवृत्ती देते. जातक कलात्मक व शैक्षणिकदृष्ट्या प्रतिभावान होतो.',pa:'ਲਗਨੇਸ਼ ਪੰਜਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਬੁੱਧੀ, ਰਚਨਾਤਮਕਤਾ, ਉੱਚ ਸਿੱਖਿਆ, ਸੰਤਾਨ, ਪਿਆਰ ਅਤੇ ਅਧਿਆਤਮਕ ਰੁਚੀ ਦਿੰਦਾ ਹੈ। ਜਾਤਕ ਕਲਾਤਮਕ ਅਤੇ ਵਿੱਦਿਅਕ ਤੌਰ ਤੇ ਪ੍ਰਤਿਭਾਸ਼ਾਲੀ ਹੁੰਦਾ ਹੈ।',gu:'લગ્નેશ પાંચમા ભાવમાં હોય તો બુદ્ધિ, સર્જનાત્મકતા, ઉચ્ચ શિક્ષણ, સંતાન, પ્રેમ અને આધ્યાત્મિક વૃત્તિ આપે છે. જાતક કલાત્મક અને શૈક્ષણિક રીતે પ્રતિભાશાળી હોય છે.'},
    6:{ta:'லக்னாதிபதி ஆறாம் பாவத்தில் இருந்தால் ஆரோக்கிய சவால்கள், எதிரிகளுடன் மோதல்கள், சட்ட தகராறுகள் மற்றும் சேவை சார்ந்த வேலையை உருவாக்குகிறது. இருப்பினும், அனைத்து தடைகளையும் வெல்லும் வலுவான போராளியையும் உருவாக்கலாம்.',te:'లగ్నాధిపతి ఆరవ భావంలో ఉంటే ఆరోగ్య సవాళ్లు, శత్రువులతో ఘర్షణలు, న్యాయ వివాదాలు మరియు సేవా-ఆధారిత పనిని సృష్టిస్తుంది. అయితే, అన్ని అడ్డంకులను అధిగమించే బలమైన పోరాట యోధుడిని కూడా తయారు చేయవచ్చు.',bn:'লগ্নেশ ষষ্ঠ ভাবে থাকলে স্বাস্থ্য চ্যালেঞ্জ, শত্রুর সাথে দ্বন্দ্ব, আইনি বিরোধ ও সেবামূলক কাজ সৃষ্টি করে। তবে সব বাধা অতিক্রমকারী শক্তিশালী যোদ্ধাও তৈরি করতে পারে।',mr:'लग्नेश सहाव्या भावात असल्यास आरोग्य आव्हाने, शत्रूंशी संघर्ष, कायदेशीर वाद व सेवाभिमुख काम निर्माण करते. तथापि, सर्व अडथळे पार करणारा बलवान योद्धाही घडवू शकते.',pa:'ਲਗਨੇਸ਼ ਛੇਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਸਿਹਤ ਚੁਣੌਤੀਆਂ, ਦੁਸ਼ਮਣਾਂ ਨਾਲ ਟਕਰਾਅ, ਕਾਨੂੰਨੀ ਝਗੜੇ ਅਤੇ ਸੇਵਾ-ਮੁਖੀ ਕੰਮ ਪੈਦਾ ਕਰਦਾ ਹੈ। ਫਿਰ ਵੀ, ਸਾਰੀਆਂ ਰੁਕਾਵਟਾਂ ਨੂੰ ਪਾਰ ਕਰਨ ਵਾਲਾ ਬਲਵਾਨ ਯੋਧਾ ਵੀ ਬਣਾ ਸਕਦਾ ਹੈ।',gu:'લગ્નેશ છઠ્ઠા ભાવમાં હોય તો આરોગ્ય પડકારો, શત્રુઓ સાથે સંઘર્ષ, કાનૂની વિવાદ અને સેવાલક્ષી કામ સર્જે છે. તેમ છતાં, બધા અવરોધો પાર કરનાર બળવાન યોદ્ધો પણ બનાવી શકે છે.'},
    7:{ta:'லக்னாதிபதி ஏழாம் பாவத்தில் இருந்தால் திருமணம், கூட்டாண்மைகள் மற்றும் பொது வாழ்க்கையை வலியுறுத்துகிறது. ஜாதகரின் அடையாளம் உறவுகளைச் சுற்றி வருகிறது. இது வணிக கூட்டாண்மைகள் மற்றும் மகிழ்ச்சியான திருமணத்திற்கு சாதகமானது.',te:'లగ్నాధిపతి ఏడవ భావంలో ఉంటే వివాహం, భాగస్వామ్యాలు మరియు ప్రజా జీవితాన్ని నొక్కి చెబుతుంది. జాతకుని గుర్తింపు సంబంధాల చుట్టూ తిరుగుతుంది. ఇది వ్యాపార భాగస్వామ్యాలకు మరియు సంతోషకరమైన వివాహానికి అనుకూలం.',bn:'লগ্নেশ সপ্তম ভাবে থাকলে বিবাহ, অংশীদারিত্ব ও জনজীবনের ওপর জোর দেয়। জাতকের পরিচয় সম্পর্ককে ঘিরে আবর্তিত হয়। এটি ব্যবসায়িক অংশীদারিত্ব ও সুখী বিবাহের জন্য অনুকূল।',mr:'लग्नेश सातव्या भावात असल्यास विवाह, भागीदारी व सार्वजनिक जीवनावर भर देते. जातकाची ओळख नात्यांभोवती फिरते. हे व्यावसायिक भागीदारी व सुखी विवाहासाठी अनुकूल आहे.',pa:'ਲਗਨੇਸ਼ ਸੱਤਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਵਿਆਹ, ਭਾਈਵਾਲੀਆਂ ਅਤੇ ਜਨਤਕ ਜੀਵਨ ਤੇ ਜ਼ੋਰ ਦਿੰਦਾ ਹੈ। ਜਾਤਕ ਦੀ ਪਛਾਣ ਰਿਸ਼ਤਿਆਂ ਦੁਆਲੇ ਘੁੰਮਦੀ ਹੈ। ਇਹ ਵਪਾਰਕ ਭਾਈਵਾਲੀਆਂ ਅਤੇ ਖੁਸ਼ਹਾਲ ਵਿਆਹ ਲਈ ਅਨੁਕੂਲ ਹੈ।',gu:'લગ્નેશ સાતમા ભાવમાં હોય તો લગ્ન, ભાગીદારી અને જાહેર જીવન પર ભાર મૂકે છે. જાતકની ઓળખ સંબંધોની આસપાસ ફરે છે. આ વ્યાવસાયિક ભાગીદારી અને સુખી લગ્ન માટે અનુકૂળ છે.'},
    8:{ta:'லக்னாதிபதி எட்டாம் பாவத்தில் இருந்தால் திடீர் மாற்றங்கள், மறைஞான ஆர்வங்கள் மற்றும் வாழ்க்கையில் மாற்றங்களைக் கொண்டுவருகிறது. ஜாதகர் நாள்பட்ட ஆரோக்கிய பிரச்சினைகளை எதிர்கொள்ளலாம் அல்லது ஆராய்ச்சி, ரகசியங்கள் மற்றும் மறைஞானத்தில் ஆர்வம் கொள்ளலாம்.',te:'లగ్నాధిపతి ఎనిమిదవ భావంలో ఉంటే ఆకస్మిక మార్పులు, గూఢ ఆసక్తులు మరియు జీవితంలో పరివర్తనలను తెస్తుంది. జాతకుడు దీర్ఘకాలిక ఆరోగ్య సమస్యలను ఎదుర్కోవచ్చు లేదా పరిశోధన, రహస్యాలు మరియు ఆధ్యాత్మికతలో ఆసక్తి కలిగి ఉండవచ్చు.',bn:'লগ্নেশ অষ্টম ভাবে থাকলে আকস্মিক পরিবর্তন, গূঢ় আগ্রহ ও জীবনে রূপান্তর আনে। জাতক দীর্ঘস্থায়ী স্বাস্থ্য সমস্যার সম্মুখীন হতে পারে বা গবেষণা, রহস্য ও অতীন্দ্রিয়বাদে আগ্রহী হতে পারে।',mr:'लग्नेश आठव्या भावात असल्यास आकस्मिक बदल, गूढ रुची व जीवनात परिवर्तन आणते. जातक दीर्घकालीन आरोग्य समस्यांना सामोरा जाऊ शकतो किंवा संशोधन, रहस्ये व गूढवादात रुची घेऊ शकतो.',pa:'ਲਗਨੇਸ਼ ਅੱਠਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਅਚਾਨਕ ਬਦਲਾਅ, ਗੂੜ੍ਹ ਰੁਚੀਆਂ ਅਤੇ ਜੀਵਨ ਵਿੱਚ ਪਰਿਵਰਤਨ ਲਿਆਉਂਦਾ ਹੈ। ਜਾਤਕ ਪੁਰਾਣੀਆਂ ਸਿਹਤ ਸਮੱਸਿਆਵਾਂ ਦਾ ਸਾਹਮਣਾ ਕਰ ਸਕਦਾ ਜਾਂ ਖੋਜ, ਰਾਜ਼ਾਂ ਅਤੇ ਗੂੜ੍ਹਵਾਦ ਵਿੱਚ ਰੁਚੀ ਲੈ ਸਕਦਾ ਹੈ।',gu:'લગ્નેશ આઠમા ભાવમાં હોય તો અચાનક ફેરફારો, ગૂઢ રસ અને જીવનમાં પરિવર્તન લાવે છે. જાતક દીર્ઘકાલીન આરોગ્ય સમસ્યાઓનો સામનો કરી શકે અથવા સંશોધન, રહસ્યો અને ગૂઢવાદમાં રસ લઈ શકે છે.'},
    9:{ta:'லக்னாதிபதி ஒன்பதாம் பாவத்தில் இருப்பது மிகவும் சுபமான அமைப்புகளில் ஒன்று. ஜாதகர் அதிர்ஷ்டசாலி, மத நம்பிக்கை, தத்துவ சிந்தனை மற்றும் தந்தை-குருக்களின் ஆதரவைப் பெறுபவராகிறார். நீண்ட பயணங்களும் ஆன்மிக வளர்ச்சியும் குறிக்கப்படுகின்றன.',te:'లగ్నాధిపతి తొమ్మిదవ భావంలో ఉండటం అత్యంత శుభ స్థానాలలో ఒకటి. జాతకుడు అదృష్టవంతుడు, మతపరుడు, తాత్వికుడు మరియు తండ్రి-గురువుల అనుగ్రహం పొందేవాడు. దీర్ఘ ప్రయాణాలు మరియు ఆధ్యాత్మిక ఎదుగుదల సూచించబడతాయి.',bn:'লগ্নেশ নবম ভাবে থাকা সবচেয়ে শুভ স্থানগুলির একটি। জাতক সৌভাগ্যবান, ধার্মিক, দার্শনিক এবং পিতা-গুরুর অনুগ্রহপ্রাপ্ত হয়। দীর্ঘ ভ্রমণ ও আধ্যাত্মিক উন্নতি নির্দেশিত হয়।',mr:'लग्नेश नवव्या भावात असणे सर्वात शुभ स्थानांपैकी एक. जातक भाग्यवान, धार्मिक, तत्त्वज्ञ व वडील-गुरूंची कृपा लाभणारा होतो. दीर्घ प्रवास व आध्यात्मिक उन्नती दर्शवली जाते.',pa:'ਲਗਨੇਸ਼ ਨੌਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਣਾ ਸਭ ਤੋਂ ਸ਼ੁਭ ਸਥਾਨਾਂ ਵਿੱਚੋਂ ਇੱਕ ਹੈ। ਜਾਤਕ ਭਾਗਸ਼ਾਲੀ, ਧਾਰਮਿਕ, ਦਾਰਸ਼ਨਿਕ ਅਤੇ ਪਿਤਾ-ਗੁਰੂਆਂ ਦੀ ਕਿਰਪਾ ਪ੍ਰਾਪਤ ਕਰਨ ਵਾਲਾ ਹੁੰਦਾ ਹੈ। ਲੰਬੇ ਸਫ਼ਰ ਅਤੇ ਅਧਿਆਤਮਕ ਵਿਕਾਸ ਸੰਕੇਤਿਤ ਹਨ।',gu:'લગ્નેશ નવમા ભાવમાં હોવું સૌથી શુભ સ્થાનોમાંનું એક છે. જાતક ભાગ્યશાળી, ધાર્મિક, દાર્શનિક અને પિતા-ગુરુની કૃપા મેળવનાર હોય છે. લાંબી મુસાફરી અને આધ્યાત્મિક વિકાસ સૂચવાય છે.'},
    10:{ta:'லக்னாதிபதி பத்தாம் பாவத்தில் இருந்தால் வலுவான தொழில், உயர் அந்தஸ்து, புகழ் மற்றும் அதிகாரத்தை அளிக்கிறது. ஜாதகர் கடின உழைப்பு மற்றும் தலைமையின் மூலம் பெரும் வெற்றியை அடைகிறார். ராஜயோக சாத்தியம் மிக அதிகம்.',te:'లగ్నాధిపతి పదవ భావంలో ఉంటే బలమైన వృత్తి, ఉన్నత హోదా, కీర్తి మరియు అధికారాన్ని ఇస్తుంది. జాతకుడు కష్టపడి పని చేయడం మరియు నాయకత్వం ద్వారా గొప్ప విజయాన్ని సాధిస్తాడు. రాజయోగ సామర్థ్యం చాలా ఎక్కువ.',bn:'লগ্নেশ দশম ভাবে থাকলে শক্তিশালী কর্মজীবন, উচ্চ মর্যাদা, খ্যাতি ও কর্তৃত্ব দেয়। জাতক কঠোর পরিশ্রম ও নেতৃত্বের মাধ্যমে মহান সাফল্য অর্জন করে। রাজযোগের সম্ভাবনা খুব বেশি।',mr:'लग्नेश दहाव्या भावात असल्यास बलवान करिअर, उच्च दर्जा, कीर्ती व अधिकार देते. जातक कठोर परिश्रम व नेतृत्वाने मोठे यश मिळवतो. राजयोगाची शक्यता खूप जास्त.',pa:'ਲਗਨੇਸ਼ ਦਸਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਮਜ਼ਬੂਤ ਕਰੀਅਰ, ਉੱਚ ਰੁਤਬਾ, ਸ਼ੋਹਰਤ ਅਤੇ ਅਧਿਕਾਰ ਦਿੰਦਾ ਹੈ। ਜਾਤਕ ਸਖ਼ਤ ਮਿਹਨਤ ਅਤੇ ਲੀਡਰਸ਼ਿਪ ਨਾਲ ਵੱਡੀ ਸਫਲਤਾ ਪ੍ਰਾਪਤ ਕਰਦਾ ਹੈ। ਰਾਜਯੋਗ ਦੀ ਸੰਭਾਵਨਾ ਬਹੁਤ ਜ਼ਿਆਦਾ ਹੈ।',gu:'લગ્નેશ દશમા ભાવમાં હોય તો બળવાન કારકિર્દી, ઉચ્ચ દરજ્જો, કીર્તિ અને અધિકાર આપે છે. જાતક સખત મહેનત અને નેતૃત્વથી મહાન સફળતા મેળવે છે. રાજયોગની સંભાવના ખૂબ વધારે.'},
    11:{ta:'லக்னாதிபதி பதினொன்றாம் பாவத்தில் இருந்தால் லாபங்கள், ஆசை நிறைவேற்றம், பெரிய சமூக வலைப்பின்னல் மற்றும் மூத்த உடன்பிறந்தோரின் ஆதரவை உருவாக்குகிறது. வலைப்பின்னல் மற்றும் குழு நடவடிக்கைகள் மூலம் நிதி லாபங்கள் முக்கியம்.',te:'లగ్నాధిపతి పదకొండవ భావంలో ఉంటే లాభాలు, కోరికల నెరవేర్పు, పెద్ద సామాజిక నెట్‌వర్క్ మరియు అన్నదమ్ముల మద్దతును సృష్టిస్తుంది. నెట్‌వర్కింగ్ మరియు సమూహ కార్యకలాపాల ద్వారా ఆర్థిక లాభాలు ప్రముఖం.',bn:'লগ্নেশ একাদশ ভাবে থাকলে লাভ, ইচ্ছাপূরণ, বড় সামাজিক নেটওয়ার্ক ও বড় ভাইবোনের সমর্থন সৃষ্টি করে। নেটওয়ার্কিং ও দলগত কার্যক্রমের মাধ্যমে আর্থিক লাভ প্রধান।',mr:'लग्नेश अकराव्या भावात असल्यास लाभ, इच्छापूर्ती, मोठे सामाजिक नेटवर्क व मोठ्या भावंडांचा पाठिंबा निर्माण करते. नेटवर्किंग व सामूहिक कार्यांतून आर्थिक लाभ प्रमुख.',pa:'ਲਗਨੇਸ਼ ਗਿਆਰਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਲਾਭ, ਇੱਛਾ ਪੂਰਤੀ, ਵੱਡਾ ਸਮਾਜਿਕ ਨੈੱਟਵਰਕ ਅਤੇ ਵੱਡੇ ਭੈਣ-ਭਰਾਵਾਂ ਦਾ ਸਹਾਰਾ ਪੈਦਾ ਕਰਦਾ ਹੈ। ਨੈੱਟਵਰਕਿੰਗ ਅਤੇ ਸਮੂਹਿਕ ਗਤੀਵਿਧੀਆਂ ਰਾਹੀਂ ਵਿੱਤੀ ਲਾਭ ਪ੍ਰਮੁੱਖ।',gu:'લગ્નેશ અગિયારમા ભાવમાં હોય તો લાભ, ઇચ્છાપૂર્તિ, મોટું સામાજિક નેટવર્ક અને મોટા ભાઈ-બહેનનો ટેકો સર્જે છે. નેટવર્કિંગ અને સામૂહિક પ્રવૃત્તિઓ દ્વારા આર્થિક લાભ પ્રમુખ.'},
    12:{ta:'லக்னாதிபதி பன்னிரண்டாம் பாவத்தில் இருந்தால் சுய இழப்பு, தனிமை, ஆன்மிக முக்தி அல்லது வெளிநாட்டு குடியேற்றத்தை ஏற்படுத்துகிறது. ஜாதகர் அடையாளம் மற்றும் ஆரோக்கியத்தில் போராடலாம் ஆனால் ஆன்மிக சாதனையில் ஆறுதலைக் காண்கிறார்.',te:'లగ్నాధిపతి పన్నెండవ భావంలో ఉంటే స్వీయ నష్టం, ఏకాంతం, ఆధ్యాత్మిక ముక్తి లేదా విదేశీ స్థిరనివాసానికి కారణమవుతుంది. జాతకుడు గుర్తింపు మరియు ఆరోగ్యంతో పోరాడవచ్చు కానీ ఆధ్యాత్మిక సాధనలో ఓదార్పును పొందుతాడు.',bn:'লগ্নেশ দ্বাদশ ভাবে থাকলে আত্মক্ষয়, নির্জনতা, আধ্যাত্মিক মুক্তি বা বিদেশে বসতি ঘটায়। জাতক পরিচয় ও স্বাস্থ্য নিয়ে সংগ্রাম করতে পারে কিন্তু আধ্যাত্মিক সাধনায় সান্ত্বনা পায়।',mr:'लग्नेश बाराव्या भावात असल्यास आत्म-हानी, एकांत, आध्यात्मिक मुक्ती किंवा परदेश वास घडवते. जातक ओळख व आरोग्याशी झुंजू शकतो पण आध्यात्मिक साधनेत दिलासा शोधतो.',pa:'ਲਗਨੇਸ਼ ਬਾਰ੍ਹਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਸਵੈ-ਹਾਨੀ, ਇਕਾਂਤ, ਅਧਿਆਤਮਕ ਮੁਕਤੀ ਜਾਂ ਵਿਦੇਸ਼ੀ ਵਸੇਬਾ ਪੈਦਾ ਕਰਦਾ ਹੈ। ਜਾਤਕ ਪਛਾਣ ਅਤੇ ਸਿਹਤ ਨਾਲ ਜੂਝ ਸਕਦਾ ਪਰ ਅਧਿਆਤਮਕ ਸਾਧਨਾ ਵਿੱਚ ਦਿਲਾਸਾ ਲੱਭਦਾ ਹੈ।',gu:'લગ્નેશ બારમા ભાવમાં હોય તો સ્વ-હાનિ, એકાંત, આધ્યાત્મિક મુક્તિ કે વિદેશ વસવાટ સર્જે છે. જાતક ઓળખ અને આરોગ્ય સાથે સંઘર્ષ કરી શકે પણ આધ્યાત્મિક સાધનામાં દિલાસો મેળવે છે.'},
  },
  2: {
    1:{ta:'தனேஷ் முதலாம் பாவத்தில் இருந்தால் ஜாதகர் கவர்ச்சிகரமான, செல்வந்தர் மற்றும் சொல்வன்மையுள்ளவராகிறார். இயற்கையாகவே வளங்களை ஈர்க்கிறார், உடல் தோற்றத்தில் அக்கறை கொள்கிறார்.',te:'ధనేశుడు మొదటి భావంలో ఉంటే జాతకుడు ఆకర్షణీయుడు, సంపన్నుడు మరియు వాక్చాతుర్యం కలిగినవాడు అవుతాడు. సహజంగా వనరులను ఆకర్షిస్తాడు, శారీరక రూపంపై శ్రద్ధ చూపుతాడు.',bn:'ধনেশ প্রথম ভাবে থাকলে জাতক আকর্ষণীয়, ধনী ও বাগ্মী হয়। স্বাভাবিকভাবে সম্পদ আকর্ষণ করে এবং দৈহিক রূপ সম্পর্কে সচেতন থাকে।',mr:'धनेश पहिल्या भावात असल्यास जातक आकर्षक, श्रीमंत व वाक्पटू होतो. नैसर्गिकरित्या संसाधने आकर्षित करतो, शारीरिक रूपाबद्दल जागरूक असतो.',pa:'ਧਨੇਸ਼ ਪਹਿਲੇ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਜਾਤਕ ਖਿੱਚ ਭਰਿਆ, ਧਨਵਾਨ ਅਤੇ ਵਾਕ-ਪਟੂ ਹੁੰਦਾ ਹੈ। ਕੁਦਰਤੀ ਤੌਰ ਤੇ ਸਾਧਨ ਖਿੱਚਦਾ ਹੈ, ਸਰੀਰਕ ਰੂਪ ਬਾਰੇ ਸੁਚੇਤ ਰਹਿੰਦਾ ਹੈ।',gu:'ધનેશ પ્રથમ ભાવમાં હોય તો જાતક આકર્ષક, ધનવાન અને વાક્પટુ હોય છે. કુદરતી રીતે સંસાધનો આકર્ષે છે, શારીરિક રૂપ વિશે સભાન રહે છે.'},
    2:{ta:'தனேஷ் தன் சொந்த பாவத்தில் இருப்பது செல்வம், குடும்ப நல்லிணக்கம் மற்றும் இனிமையான பேச்சுக்கு உகந்தது. ஜாதகர் கணிசமான சொத்துக்களைச் சேர்க்கிறார், நிலையான குடும்ப வாழ்க்கை உண்டு.',te:'ధనేశుడు తన స్వంత భావంలో ఉండటం సంపద, కుటుంబ సామరస్యం మరియు మధురమైన మాటకు అనుకూలం. జాతకుడు గణనీయమైన ఆస్తులను సంపాదిస్తాడు, స్థిరమైన కుటుంబ జీవితం ఉంటుంది.',bn:'ধনেশ নিজ ভাবে থাকা সম্পদ, পারিবারিক সম্প্রীতি ও মধুর বাক্যের জন্য উত্তম। জাতক যথেষ্ট সম্পদ সঞ্চয় করে ও স্থিতিশীল পারিবারিক জীবন লাভ করে।',mr:'धनेश स्वतःच्या भावात असणे संपत्ती, कौटुंबिक सामंजस्य व मधुर वाणीसाठी उत्तम. जातक भरीव मालमत्ता संचय करतो व स्थिर कौटुंबिक जीवन लाभते.',pa:'ਧਨੇਸ਼ ਆਪਣੇ ਭਾਵ ਵਿੱਚ ਹੋਣਾ ਦੌਲਤ, ਪਰਿਵਾਰਕ ਸਦਭਾਵਨਾ ਅਤੇ ਮਿੱਠੀ ਬੋਲੀ ਲਈ ਵਧੀਆ। ਜਾਤਕ ਕਾਫ਼ੀ ਜਾਇਦਾਦ ਸੰਚਯ ਕਰਦਾ ਅਤੇ ਸਥਿਰ ਪਰਿਵਾਰਕ ਜੀਵਨ ਲਾਭਦਾ ਹੈ।',gu:'ધનેશ પોતાના ભાવમાં હોવું સંપત્તિ, કૌટુંબિક સંવાદિતા અને મધુર વાણી માટે ઉત્તમ. જાતક નોંધપાત્ર મિલકત સંચય કરે અને સ્થિર કૌટુંબિક જીવન મેળવે છે.'},
    3:{ta:'தனேஷ் மூன்றாம் பாவத்தில் இருந்தால் தொடர்பு, எழுத்து, ஊடகம் மற்றும் குறுகிய பயணங்களின் மூலம் வருமானம் கிடைக்கிறது. ஜாதகர் உடன்பிறந்தோர் மூலம் சம்பாதிக்கிறார், நம்பவைக்கும் வணிக பேச்சு உண்டு.',te:'ధనేశుడు మూడవ భావంలో ఉంటే సంభాషణ, రచన, మీడియా మరియు చిన్న ప్రయాణాల ద్వారా ఆదాయం లభిస్తుంది. జాతకుడు సహోదరుల ద్వారా సంపాదిస్తాడు, ఒప్పించే వ్యాపార మాట కలిగి ఉంటాడు.',bn:'ধনেশ তৃতীয় ভাবে থাকলে যোগাযোগ, লেখা, মিডিয়া ও স্বল্প ভ্রমণের মাধ্যমে আয় হয়। জাতক ভাইবোনের মাধ্যমে উপার্জন করে ও প্ররোচক ব্যবসায়িক বাক্য থাকে।',mr:'धनेश तिसऱ्या भावात असल्यास संवाद, लेखन, माध्यम व लहान प्रवासातून उत्पन्न मिळते. जातक भावंडांमार्फत कमावतो, मन वळवणारी व्यावसायिक वाणी असते.',pa:'ਧਨੇਸ਼ ਤੀਜੇ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਸੰਚਾਰ, ਲਿਖਤ, ਮੀਡੀਆ ਅਤੇ ਛੋਟੇ ਸਫ਼ਰਾਂ ਰਾਹੀਂ ਆਮਦਨ ਮਿਲਦੀ ਹੈ। ਜਾਤਕ ਭੈਣ-ਭਰਾਵਾਂ ਰਾਹੀਂ ਕਮਾਉਂਦਾ, ਮਨਾਉਣ ਵਾਲੀ ਵਪਾਰਕ ਬੋਲੀ ਹੁੰਦੀ ਹੈ।',gu:'ધનેશ ત્રીજા ભાવમાં હોય તો સંવાદ, લેખન, મીડિયા અને ટૂંકી મુસાફરી દ્વારા આવક મળે છે. જાતક ભાઈ-બહેન દ્વારા કમાય, સમજાવટભરી વ્યાવસાયિક વાણી હોય છે.'},
    4:{ta:'தனேஷ் நான்காம் பாவத்தில் இருந்தால் அசையாச் சொத்து, விவசாயம் மற்றும் தாய்வழி மூலம் செல்வம் வருகிறது. ஜாதகருக்கு வசதியான வீடு, நல்ல வாகனங்கள் மற்றும் குடும்ப செல்வத்துடன் இணைந்த உணர்வு பாதுகாப்பு உண்டு.',te:'ధనేశుడు నాల్గవ భావంలో ఉంటే స్థిరాస్తి, వ్యవసాయం మరియు తల్లి వైపు నుండి సంపద వస్తుంది. జాతకుడికి సౌకర్యవంతమైన ఇల్లు, మంచి వాహనాలు మరియు కుటుంబ సంపదతో ముడిపడిన భావోద్వేగ భద్రత ఉంటుంది.',bn:'ধনেশ চতুর্থ ভাবে থাকলে স্থাবর সম্পত্তি, কৃষি ও মাতৃপক্ষ থেকে সম্পদ আসে। জাতকের আরামদায়ক বাড়ি, ভালো যানবাহন ও পারিবারিক সম্পদের সাথে যুক্ত আবেগীয় নিরাপত্তা থাকে।',mr:'धनेश चौथ्या भावात असल्यास स्थावर मालमत्ता, शेती व मातृपक्षाकडून संपत्ती येते. जातकाला आरामदायी घर, चांगली वाहने व कौटुंबिक संपत्तीशी जोडलेली भावनिक सुरक्षा असते.',pa:'ਧਨੇਸ਼ ਚੌਥੇ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਅਚੱਲ ਜਾਇਦਾਦ, ਖੇਤੀ ਅਤੇ ਮਾਤਾ ਦੇ ਪਾਸਿਓਂ ਦੌਲਤ ਆਉਂਦੀ ਹੈ। ਜਾਤਕ ਨੂੰ ਆਰਾਮਦਾਇਕ ਘਰ, ਚੰਗੇ ਵਾਹਨ ਅਤੇ ਪਰਿਵਾਰਕ ਦੌਲਤ ਨਾਲ ਜੁੜੀ ਭਾਵਨਾਤਮਕ ਸੁਰੱਖਿਆ ਹੁੰਦੀ ਹੈ।',gu:'ધનેશ ચોથા ભાવમાં હોય તો સ્થાવર મિલકત, ખેતી અને માતૃપક્ષથી સંપત્તિ આવે છે. જાતકને આરામદાયક ઘર, સારા વાહનો અને કૌટુંબિક સંપત્તિ સાથે જોડાયેલી ભાવનાત્મક સુરક્ષા હોય છે.'},
    5:{ta:'தனேஷ் ஐந்தாம் பாவத்தில் இருந்தால் சூதாட்டம், பங்குகள், கல்வி, குழந்தைகள் மற்றும் படைப்புக் கலைகள் மூலம் லாபம் கிடைக்கிறது. ஜாதகர் பொழுதுபோக்கு அல்லது கற்பித்தல் மூலம் சம்பாதிக்கலாம்.',te:'ధనేశుడు ఐదవ భావంలో ఉంటే ఊహాజల్పన, షేర్లు, విద్య, పిల్లలు మరియు సృజనాత్మక కళల ద్వారా లాభం లభిస్తుంది. జాతకుడు వినోదం లేదా బోధన ద్వారా సంపాదించవచ్చు.',bn:'ধনেশ পঞ্চম ভাবে থাকলে ফাটকা, শেয়ার, শিক্ষা, সন্তান ও সৃজনশীল কলার মাধ্যমে লাভ হয়। জাতক বিনোদন বা শিক্ষকতার মাধ্যমে উপার্জন করতে পারে।',mr:'धनेश पाचव्या भावात असल्यास सट्टा, शेअर, शिक्षण, संतती व सर्जनशील कलांतून लाभ मिळतो. जातक मनोरंजन किंवा अध्यापनातून कमावू शकतो.',pa:'ਧਨੇਸ਼ ਪੰਜਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਸੱਟਾ, ਸ਼ੇਅਰ, ਸਿੱਖਿਆ, ਸੰਤਾਨ ਅਤੇ ਰਚਨਾਤਮਕ ਕਲਾਵਾਂ ਰਾਹੀਂ ਲਾਭ ਮਿਲਦਾ ਹੈ। ਜਾਤਕ ਮਨੋਰੰਜਨ ਜਾਂ ਅਧਿਆਪਨ ਰਾਹੀਂ ਕਮਾ ਸਕਦਾ ਹੈ।',gu:'ધનેશ પાંચમા ભાવમાં હોય તો સટ્ટા, શેર, શિક્ષણ, સંતાન અને સર્જનાત્મક કલાઓ દ્વારા લાભ મળે છે. જાતક મનોરંજન કે અધ્યાપન દ્વારા કમાઈ શકે છે.'},
    6:{ta:'தனேஷ் ஆறாம் பாவத்தில் இருந்தால் ஆரோக்கியம், கடன்கள் மற்றும் பணம் தொடர்பான தகராறுகளுக்கு செலவாகிறது. சேவை, மருத்துவம் அல்லது சட்டப் பணி மூலம் செல்வம் வரலாம், ஆனால் நிதி நிலைத்தன்மைக்கு முயற்சி தேவை.',te:'ధనేశుడు ఆరవ భావంలో ఉంటే ఆరోగ్యం, అప్పులు మరియు డబ్బు సంబంధిత వివాదాలపై ఖర్చు అవుతుంది. సేవ, వైద్యం లేదా న్యాయ పని ద్వారా సంపద రావచ్చు, కానీ ఆర్థిక స్థిరత్వానికి కృషి అవసరం.',bn:'ধনেশ ষষ্ঠ ভাবে থাকলে স্বাস্থ্য, ঋণ ও অর্থ সংক্রান্ত বিরোধে ব্যয় হয়। সেবা, চিকিৎসা বা আইনি কাজের মাধ্যমে সম্পদ আসতে পারে, তবে আর্থিক স্থিতিশীলতার জন্য প্রচেষ্টা প্রয়োজন।',mr:'धनेश सहाव्या भावात असल्यास आरोग्य, कर्ज व पैसा संबंधित वादांवर खर्च होतो. सेवा, वैद्यक किंवा कायदेशीर कामातून संपत्ती येऊ शकते, पण आर्थिक स्थिरतेसाठी प्रयत्न आवश्यक.',pa:'ਧਨੇਸ਼ ਛੇਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਸਿਹਤ, ਕਰਜ਼ ਅਤੇ ਪੈਸੇ ਸੰਬੰਧੀ ਝਗੜਿਆਂ ਤੇ ਖਰਚ ਹੁੰਦਾ ਹੈ। ਸੇਵਾ, ਦਵਾਈ ਜਾਂ ਕਾਨੂੰਨੀ ਕੰਮ ਰਾਹੀਂ ਦੌਲਤ ਆ ਸਕਦੀ, ਪਰ ਵਿੱਤੀ ਸਥਿਰਤਾ ਲਈ ਯਤਨ ਲੋੜੀਂਦਾ।',gu:'ધનેશ છઠ્ઠા ભાવમાં હોય તો આરોગ્ય, દેવું અને પૈસા સંબંધિત વિવાદો પર ખર્ચ થાય છે. સેવા, દવા કે કાનૂની કામ દ્વારા સંપત્તિ આવી શકે, પણ આર્થિક સ્થિરતા માટે પ્રયત્ન જરૂરી.'},
    7:{ta:'தனேஷ் ஏழாம் பாவத்தில் இருந்தால் கூட்டாண்மைகள், வாழ்க்கைத்துணையின் செல்வம் மற்றும் வணிக பரிவர்த்தனைகள் மூலம் வருமானம் வருகிறது. வாழ்க்கைத்துணை பொருளாதார ரீதியில் வளமானவராகவும் குடும்ப செழிப்பிற்கு பங்களிப்பவராகவும் இருக்கலாம்.',te:'ధనేశుడు ఏడవ భావంలో ఉంటే భాగస్వామ్యాలు, జీవిత భాగస్వామి సంపద మరియు వ్యాపార లావాదేవీల ద్వారా ఆదాయం వస్తుంది. జీవిత భాగస్వామి ఆర్థికంగా సంపన్నుడై కుటుంబ సమృద్ధికి గణనీయంగా దోహదపడవచ్చు.',bn:'ধনেশ সপ্তম ভাবে থাকলে অংশীদারিত্ব, জীবনসঙ্গীর সম্পদ ও ব্যবসায়িক লেনদেনের মাধ্যমে আয় হয়। জীবনসঙ্গী আর্থিকভাবে সচ্ছল হতে পারে ও পারিবারিক সমৃদ্ধিতে উল্লেখযোগ্য অবদান রাখে।',mr:'धनेश सातव्या भावात असल्यास भागीदारी, जोडीदाराची संपत्ती व व्यापारी व्यवहारांतून उत्पन्न येते. जोडीदार आर्थिकदृष्ट्या संपन्न असून कौटुंबिक समृद्धीत लक्षणीय योगदान देऊ शकतो.',pa:'ਧਨੇਸ਼ ਸੱਤਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਭਾਈਵਾਲੀਆਂ, ਜੀਵਨ ਸਾਥੀ ਦੀ ਦੌਲਤ ਅਤੇ ਵਪਾਰਕ ਲੈਣ-ਦੇਣ ਰਾਹੀਂ ਆਮਦਨ ਆਉਂਦੀ ਹੈ। ਜੀਵਨ ਸਾਥੀ ਆਰਥਿਕ ਤੌਰ ਤੇ ਸੰਪੰਨ ਹੋ ਕੇ ਪਰਿਵਾਰਕ ਖੁਸ਼ਹਾਲੀ ਵਿੱਚ ਵੱਡਾ ਯੋਗਦਾਨ ਦੇ ਸਕਦਾ ਹੈ।',gu:'ધનેશ સાતમા ભાવમાં હોય તો ભાગીદારી, જીવનસાથીની સંપત્તિ અને વ્યાવસાયિક વ્યવહારો દ્વારા આવક આવે છે. જીવનસાથી આર્થિક રીતે સંપન્ન હોઈ કૌટુંબિક સમૃદ્ધિમાં નોંધપાત્ર યોગદાન આપી શકે.'},
    8:{ta:'தனேஷ் எட்டாம் பாவத்தில் இருந்தால் திடீர் நிதி லாபங்கள் அல்லது இழப்புகள், வாரிசு, காப்பீடு மற்றும் மறைவான செல்வம் ஏற்படுகிறது. ஜாதகர் பிறருடைய பணத்துடன் தொடர்புடைய வேலைகளில் ஈடுபடலாம் அல்லது நிலையற்ற நிதி வாழ்க்கை உண்டு.',te:'ధనేశుడు ఎనిమిదవ భావంలో ఉంటే ఆకస్మిక ఆర్థిక లాభాలు లేదా నష్టాలు, వారసత్వం, బీమా మరియు గుప్త సంపద కలుగుతాయి. జాతకుడు ఇతరుల డబ్బుతో వ్యవహరించవచ్చు లేదా అస్థిర ఆర్థిక జీవితం కలిగి ఉండవచ్చు.',bn:'ধনেশ অষ্টম ভাবে থাকলে আকস্মিক আর্থিক লাভ বা ক্ষতি, উত্তরাধিকার, বীমা ও গুপ্ত সম্পদ ঘটে। জাতক অন্যের অর্থ নিয়ে কাজ করতে পারে বা অনিয়মিত আর্থিক জীবন থাকতে পারে।',mr:'धनेश आठव्या भावात असल्यास आकस्मिक आर्थिक लाभ किंवा हानी, वारसा, विमा व गुप्त संपत्ती घडते. जातक इतरांच्या पैशाशी संबंधित कामांत गुंतू शकतो किंवा अस्थिर आर्थिक जीवन असू शकते.',pa:'ਧਨੇਸ਼ ਅੱਠਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਅਚਾਨਕ ਆਰਥਿਕ ਲਾਭ ਜਾਂ ਨੁਕਸਾਨ, ਵਿਰਾਸਤ, ਬੀਮਾ ਅਤੇ ਗੁਪਤ ਦੌਲਤ ਹੁੰਦੀ ਹੈ। ਜਾਤਕ ਦੂਜਿਆਂ ਦੇ ਪੈਸੇ ਨਾਲ ਸੰਬੰਧਿਤ ਕੰਮਾਂ ਵਿੱਚ ਲੱਗ ਸਕਦਾ ਜਾਂ ਅਸਥਿਰ ਵਿੱਤੀ ਜੀਵਨ ਹੋ ਸਕਦਾ ਹੈ।',gu:'ધનેશ આઠમા ભાવમાં હોય તો અચાનક આર્થિક લાભ કે નુકસાન, વારસો, વીમો અને ગુપ્ત સંપત્તિ થાય છે. જાતક બીજાના પૈસા સાથે સંબંધિત કામમાં જોડાઈ શકે અથવા અસ્થિર આર્થિક જીવન હોઈ શકે.'},
    9:{ta:'தனேஷ் ஒன்பதாம் பாவத்தில் இருந்தால் தந்தை, வெளிநாடு, மத நிறுவனங்கள், பதிப்பு மற்றும் உயர் கல்வி மூலம் செல்வம் வருகிறது. ஜாதகர் தத்துவ நாட்டம் கொண்டவராகவும் நேர்மையாக சம்பாதிப்பவராகவும் இருக்கிறார்.',te:'ధనేశుడు తొమ్మిదవ భావంలో ఉంటే తండ్రి, విదేశాలు, మత సంస్థలు, ప్రచురణ మరియు ఉన్నత విద్య ద్వారా సంపద వస్తుంది. జాతకుడు తాత్విక ప్రవృత్తి కలిగి నైతికంగా సంపాదిస్తాడు.',bn:'ধনেশ নবম ভাবে থাকলে পিতা, বিদেশ, ধর্মীয় প্রতিষ্ঠান, প্রকাশনা ও উচ্চশিক্ষার মাধ্যমে সম্পদ আসে। জাতক দার্শনিক প্রবণতাসম্পন্ন ও নৈতিকভাবে উপার্জন করে।',mr:'धनेश नवव्या भावात असल्यास वडील, परदेश, धार्मिक संस्था, प्रकाशन व उच्च शिक्षणातून संपत्ती येते. जातक तात्त्विक प्रवृत्तीचा असून नैतिकपणे कमावतो.',pa:'ਧਨੇਸ਼ ਨੌਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਪਿਤਾ, ਵਿਦੇਸ਼, ਧਾਰਮਿਕ ਸੰਸਥਾਵਾਂ, ਪ੍ਰਕਾਸ਼ਨ ਅਤੇ ਉੱਚ ਸਿੱਖਿਆ ਰਾਹੀਂ ਦੌਲਤ ਆਉਂਦੀ ਹੈ। ਜਾਤਕ ਦਾਰਸ਼ਨਿਕ ਪ੍ਰਵਿਰਤੀ ਵਾਲਾ ਹੋ ਕੇ ਨੈਤਿਕ ਤੌਰ ਤੇ ਕਮਾਉਂਦਾ ਹੈ।',gu:'ધનેશ નવમા ભાવમાં હોય તો પિતા, વિદેશ, ધાર્મિક સંસ્થાઓ, પ્રકાશન અને ઉચ્ચ શિક્ષણ દ્વારા સંપત્તિ આવે છે. જાતક દાર્શનિક વૃત્તિ ધરાવતો અને નૈતિક રીતે કમાય છે.'},
    10:{ta:'தனேஷ் பத்தாம் பாவத்தில் இருந்தால் தொழில், அரசாங்கம் மற்றும் பொது அந்தஸ்து மூலம் வருமானம் வருகிறது. ஜாதகரின் தொழில் நேரடியாக நிதி வளர்ச்சி மற்றும் குடும்ப நலனுக்கு ஆதரவளிக்கிறது.',te:'ధనేశుడు పదవ భావంలో ఉంటే వృత్తి, ప్రభుత్వం మరియు ప్రజా హోదా ద్వారా ఆదాయం వస్తుంది. జాతకుని వృత్తి నేరుగా ఆర్థిక ఎదుగుదల మరియు కుటుంబ శ్రేయస్సుకు మద్దతునిస్తుంది.',bn:'ধনেশ দশম ভাবে থাকলে কর্মজীবন, সরকার ও জনমর্যাদার মাধ্যমে আয় হয়। জাতকের পেশা সরাসরি আর্থিক বৃদ্ধি ও পারিবারিক কল্যাণে সহায়ক।',mr:'धनेश दहाव्या भावात असल्यास करिअर, सरकार व सार्वजनिक दर्जातून उत्पन्न येते. जातकाचा व्यवसाय थेट आर्थिक वाढ व कौटुंबिक कल्याणाला आधार देतो.',pa:'ਧਨੇਸ਼ ਦਸਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਕਰੀਅਰ, ਸਰਕਾਰ ਅਤੇ ਜਨਤਕ ਰੁਤਬੇ ਰਾਹੀਂ ਆਮਦਨ ਆਉਂਦੀ ਹੈ। ਜਾਤਕ ਦਾ ਪੇਸ਼ਾ ਸਿੱਧਾ ਵਿੱਤੀ ਵਾਧੇ ਅਤੇ ਪਰਿਵਾਰਕ ਭਲਾਈ ਨੂੰ ਸਹਾਰਾ ਦਿੰਦਾ ਹੈ।',gu:'ધનેશ દશમા ભાવમાં હોય તો કારકિર્દી, સરકાર અને જાહેર દરજ્જા દ્વારા આવક આવે છે. જાતકનો વ્યવસાય સીધો આર્થિક વૃદ્ધિ અને કૌટુંબિક કલ્યાણને આધાર આપે છે.'},
    11:{ta:'தனேஷ் பதினொன்றாம் பாவத்தில் இருப்பது செல்வ சேமிப்பு, மூத்த உடன்பிறந்தோர் மூலம் லாபம், பெரிய சமூக வட்டம் மற்றும் நிதி இலக்குகளின் நிறைவேற்றத்திற்கு மிகவும் சாதகமானது.',te:'ధనేశుడు పదకొండవ భావంలో ఉండటం సంపద సంచయం, అన్నదమ్ముల ద్వారా లాభం, పెద్ద సామాజిక వర్గం మరియు ఆర్థిక లక్ష్యాల నెరవేర్పుకు అత్యంత అనుకూలం.',bn:'ধনেশ একাদশ ভাবে থাকা সম্পদ সঞ্চয়, বড় ভাইবোনের মাধ্যমে লাভ, বড় সামাজিক বৃত্ত ও আর্থিক লক্ষ্য পূরণের জন্য অত্যন্ত অনুকূল।',mr:'धनेश अकराव्या भावात असणे संपत्ती संचय, मोठ्या भावंडांमार्फत लाभ, मोठे सामाजिक वर्तुळ व आर्थिक ध्येयपूर्तीसाठी अत्यंत अनुकूल.',pa:'ਧਨੇਸ਼ ਗਿਆਰਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਣਾ ਦੌਲਤ ਸੰਚਯ, ਵੱਡੇ ਭੈਣ-ਭਰਾਵਾਂ ਰਾਹੀਂ ਲਾਭ, ਵੱਡੇ ਸਮਾਜਿਕ ਦਾਇਰੇ ਅਤੇ ਵਿੱਤੀ ਟੀਚਿਆਂ ਦੀ ਪੂਰਤੀ ਲਈ ਬਹੁਤ ਅਨੁਕੂਲ।',gu:'ધનેશ અગિયારમા ભાવમાં હોવું સંપત્તિ સંચય, મોટા ભાઈ-બહેન દ્વારા લાભ, મોટા સામાજિક વર્તુળ અને આર્થિક લક્ષ્યપૂર્તિ માટે અત્યંત અનુકૂળ.'},
    12:{ta:'தனேஷ் பன்னிரண்டாம் பாவத்தில் இருந்தால் நிதி செலவுகள், செல்வ இழப்பு மற்றும் சாத்தியமான வெளிநாட்டு வருமானம் ஏற்படுகிறது. வரும் அளவுக்கு வேகமாக பணம் வெளியேறலாம்; வெளிநாட்டு வணிகம் அல்லது ஆன்மிக செலவு பொதுவானது.',te:'ధనేశుడు పన్నెండవ భావంలో ఉంటే ఆర్థిక ఖర్చులు, సంపద నష్టం మరియు సాధ్యమైన విదేశీ ఆదాయం కలుగుతాయి. వచ్చినంత వేగంగా డబ్బు బయటకు పోవచ్చు; విదేశీ వ్యాపారం లేదా ఆధ్యాత్మిక ఖర్చు సాధారణం.',bn:'ধনেশ দ্বাদশ ভাবে থাকলে আর্থিক ব্যয়, সম্পদ ক্ষতি ও সম্ভাব্য বিদেশি আয় ঘটে। আসার মতোই দ্রুত অর্থ বেরিয়ে যেতে পারে; বিদেশি বাণিজ্য বা আধ্যাত্মিক ব্যয় সাধারণ।',mr:'धनेश बाराव्या भावात असल्यास आर्थिक व्यय, संपत्ती हानी व संभाव्य परदेशी उत्पन्न घडते. येते तितक्याच वेगाने पैसा बाहेर जाऊ शकतो; परदेश व्यापार किंवा आध्यात्मिक खर्च सामान्य.',pa:'ਧਨੇਸ਼ ਬਾਰ੍ਹਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਆਰਥਿਕ ਖਰਚ, ਦੌਲਤ ਹਾਨੀ ਅਤੇ ਸੰਭਾਵੀ ਵਿਦੇਸ਼ੀ ਆਮਦਨ ਹੁੰਦੀ ਹੈ। ਆਉਣ ਜਿੰਨੀ ਤੇਜ਼ੀ ਨਾਲ ਪੈਸਾ ਬਾਹਰ ਜਾ ਸਕਦਾ; ਵਿਦੇਸ਼ੀ ਵਪਾਰ ਜਾਂ ਅਧਿਆਤਮਕ ਖਰਚ ਆਮ।',gu:'ધનેશ બારમા ભાવમાં હોય તો આર્થિક ખર્ચ, સંપત્તિ હાનિ અને સંભવિત વિદેશી આવક થાય છે. આવે તેટલી ઝડપે પૈસા બહાર જઈ શકે; વિદેશી વેપાર કે આધ્યાત્મિક ખર્ચ સામાન્ય.'},
  },
  3: {
    1:{ta:'சஹஜேஷ் முதலாம் பாவத்தில் இருந்தால் ஜாதகர் தைரியசாலி, தொடர்புத் திறன் கொண்ட, கை வேலையில் திறமையான மற்றும் விளையாட்டு-ஊடகத்தில் நாட்டம் கொண்டவராகிறார். உடன்பிறந்தோர் உறவு ஆளுமையை வலுவாக பாதிக்கிறது.',te:'సహజేశుడు మొదటి భావంలో ఉంటే జాతకుడు ధైర్యవంతుడు, సంభాషణ శీలి, చేతి పనిలో నేర్పరి మరియు క్రీడలు-మీడియా వైపు మొగ్గు కలిగి ఉంటాడు. సహోదర సంబంధాలు వ్యక్తిత్వాన్ని బలంగా ప్రభావితం చేస్తాయి.',bn:'সহজেশ প্রথম ভাবে থাকলে জাতক সাহসী, যোগাযোগপ্রবণ, হাতের কাজে দক্ষ ও খেলা-মিডিয়ার প্রতি ঝোঁকযুক্ত হয়। ভাইবোনের সম্পর্ক ব্যক্তিত্বকে দৃঢ়ভাবে প্রভাবিত করে।',mr:'सहजेश पहिल्या भावात असल्यास जातक धाडसी, संवादशील, हस्त-कुशल व खेळ-माध्यमाकडे कल असणारा होतो. भावंड नाती व्यक्तिमत्त्वावर दृढ प्रभाव टाकतात.',pa:'ਸਹਜੇਸ਼ ਪਹਿਲੇ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਜਾਤਕ ਬਹਾਦਰ, ਸੰਚਾਰਸ਼ੀਲ, ਹੱਥ ਦੇ ਕੰਮ ਵਿੱਚ ਨਿਪੁੰਨ ਅਤੇ ਖੇਡ-ਮੀਡੀਆ ਵੱਲ ਝੁਕਾਅ ਵਾਲਾ ਹੁੰਦਾ ਹੈ। ਭੈਣ-ਭਰਾ ਰਿਸ਼ਤੇ ਸ਼ਖਸੀਅਤ ਤੇ ਡੂੰਘਾ ਅਸਰ ਪਾਉਂਦੇ ਹਨ।',gu:'સહજેશ પ્રથમ ભાવમાં હોય તો જાતક હિંમતવાન, સંવાદશીલ, હાથ કામમાં નિપુણ અને રમત-મીડિયા તરફ ઝોક ધરાવતો હોય છે. ભાઈ-બહેન સંબંધ વ્યક્તિત્વને દૃઢપણે અસર કરે છે.'},
    2:{ta:'சஹஜேஷ் இரண்டாம் பாவத்தில் இருந்தால் தொடர்பு மற்றும் உடன்பிறந்தோர் செல்வம் மற்றும் குடும்ப பேச்சுடன் இணைகிறது. ஜாதகர் எழுத்து, வர்த்தகம் அல்லது குரல் சார்ந்த தொழில்கள் மூலம் சம்பாதிக்கலாம்.',te:'సహజేశుడు రెండవ భావంలో ఉంటే సంభాషణ మరియు సహోదరులు సంపద మరియు కుటుంబ మాటతో ముడిపడతారు. జాతకుడు రచన, వాణిజ్యం లేదా స్వర సంబంధ వృత్తుల ద్వారా సంపాదించవచ్చు.',bn:'সহজেশ দ্বিতীয় ভাবে থাকলে যোগাযোগ ও ভাইবোন সম্পদ ও পারিবারিক বাক্যের সাথে যুক্ত হয়। জাতক লেখা, বাণিজ্য বা কণ্ঠ-সম্পর্কিত পেশার মাধ্যমে উপার্জন করতে পারে।',mr:'सहजेश दुसऱ्या भावात असल्यास संवाद व भावंडे संपत्ती व कौटुंबिक वाणीशी जोडली जातात. जातक लेखन, व्यापार किंवा आवाज-संबंधित व्यवसायांतून कमावू शकतो.',pa:'ਸਹਜੇਸ਼ ਦੂਜੇ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਸੰਚਾਰ ਅਤੇ ਭੈਣ-ਭਰਾ ਦੌਲਤ ਅਤੇ ਪਰਿਵਾਰਕ ਬੋਲੀ ਨਾਲ ਜੁੜਦੇ ਹਨ। ਜਾਤਕ ਲਿਖਤ, ਵਪਾਰ ਜਾਂ ਆਵਾਜ਼-ਸੰਬੰਧੀ ਪੇਸ਼ਿਆਂ ਰਾਹੀਂ ਕਮਾ ਸਕਦਾ ਹੈ।',gu:'સહજેશ બીજા ભાવમાં હોય તો સંવાદ અને ભાઈ-બહેન સંપત્તિ અને કૌટુંબિક વાણી સાથે જોડાય છે. જાતક લેખન, વેપાર કે અવાજ-સંબંધિત વ્યવસાયો દ્વારા કમાઈ શકે.'},
    3:{ta:'சஹஜேஷ் தன் சொந்த பாவத்தில் இருப்பது தைரியம், தொடர்பு, உடன்பிறந்தோர் பிணைப்பு மற்றும் சுய-வெளிப்பாட்டை வலுவாக பலப்படுத்துகிறது. ஜாதகர் எழுத்து, பத்திரிகை அல்லது நடிப்புக் கலைகளில் சிறந்து விளங்கலாம்.',te:'సహజేశుడు తన స్వంత భావంలో ఉండటం ధైర్యం, సంభాషణ, సహోదర బంధాలు మరియు స్వీయ-వ్యక్తీకరణను బలంగా బలపరుస్తుంది. జాతకుడు రచన, పాత్రికేయం లేదా ప్రదర్శన కళలలో రాణించవచ్చు.',bn:'সহজেশ নিজ ভাবে থাকা সাহস, যোগাযোগ, ভাইবোন বন্ধন ও আত্মপ্রকাশকে দৃঢ়ভাবে শক্তিশালী করে। জাতক লেখা, সাংবাদিকতা বা অভিনয় কলায় উৎকর্ষ লাভ করতে পারে।',mr:'सहजेश स्वतःच्या भावात असणे धैर्य, संवाद, भावंड बंध व आत्म-अभिव्यक्ती दृढपणे बळकट करते. जातक लेखन, पत्रकारिता किंवा अभिनय कलांत उत्कृष्ट होऊ शकतो.',pa:'ਸਹਜੇਸ਼ ਆਪਣੇ ਭਾਵ ਵਿੱਚ ਹੋਣਾ ਹੌਸਲਾ, ਸੰਚਾਰ, ਭੈਣ-ਭਰਾ ਬੰਧਨ ਅਤੇ ਸਵੈ-ਪ੍ਰਗਟਾਵਾ ਮਜ਼ਬੂਤੀ ਨਾਲ ਪੱਕਾ ਕਰਦਾ ਹੈ। ਜਾਤਕ ਲਿਖਤ, ਪੱਤਰਕਾਰੀ ਜਾਂ ਅਦਾਕਾਰੀ ਕਲਾਵਾਂ ਵਿੱਚ ਉੱਤਮ ਹੋ ਸਕਦਾ ਹੈ।',gu:'સહજેશ પોતાના ભાવમાં હોવું હિંમત, સંવાદ, ભાઈ-બહેન બંધન અને સ્વ-અભિવ્યક્તિને દૃઢપણે મજબૂત કરે છે. જાતક લેખન, પત્રકારત્વ કે અભિનય કલાઓમાં ઉત્કૃષ્ટ થઈ શકે.'},
    4:{ta:'சஹஜேஷ் நான்காம் பாவத்தில் இருந்தால் தைரியமும் திறமையும் வீட்டுத் துறைக்கு வருகின்றன. ஜாதகர் வீடு மற்றும் தாயைப் பாதுகாப்பவராகவும், அசையாச் சொத்து, விருந்தோம்பல் அல்லது வீட்டு அடிப்படையிலான வணிகத்தில் பணிபுரிபவராகவும் இருக்கலாம்.',te:'సహజేశుడు నాల్గవ భావంలో ఉంటే ధైర్యం మరియు నైపుణ్యం గృహ రంగంలోకి వస్తాయి. జాతకుడు ఇల్లు మరియు తల్లిని రక్షించేవాడై, స్థిరాస్తి, ఆతిథ్యం లేదా గృహ-ఆధారిత వ్యాపారంలో పని చేయవచ్చు.',bn:'সহজেশ চতুর্থ ভাবে থাকলে সাহস ও দক্ষতা গৃহক্ষেত্রে আসে। জাতক বাড়ি ও মাতার রক্ষক হয় এবং স্থাবর সম্পত্তি, আতিথেয়তা বা গৃহভিত্তিক ব্যবসায় কাজ করতে পারে।',mr:'सहजेश चौथ्या भावात असल्यास धैर्य व कौशल्य गृहक्षेत्रात येते. जातक घर व मातेचा रक्षक होतो आणि स्थावर मालमत्ता, आदरातिथ्य किंवा घर-आधारित व्यवसायात काम करू शकतो.',pa:'ਸਹਜੇਸ਼ ਚੌਥੇ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਹੌਸਲਾ ਅਤੇ ਹੁਨਰ ਘਰੇਲੂ ਖੇਤਰ ਵਿੱਚ ਆਉਂਦੇ ਹਨ। ਜਾਤਕ ਘਰ ਅਤੇ ਮਾਂ ਦਾ ਰਾਖਾ ਹੋ ਕੇ ਅਚੱਲ ਜਾਇਦਾਦ, ਮਹਿਮਾਨਨਿਵਾਜ਼ੀ ਜਾਂ ਘਰ-ਆਧਾਰਿਤ ਵਪਾਰ ਵਿੱਚ ਕੰਮ ਕਰ ਸਕਦਾ ਹੈ।',gu:'સહજેશ ચોથા ભાવમાં હોય તો હિંમત અને કૌશલ્ય ગૃહક્ષેત્રમાં આવે છે. જાતક ઘર અને માતાનો રક્ષક બની સ્થાવર મિલકત, આતિથ્ય કે ઘર-આધારિત વ્યવસાયમાં કામ કરી શકે.'},
    5:{ta:'சஹஜேஷ் ஐந்தாம் பாவத்தில் இருந்தால் தொடர்புத் திறன் படைப்பாற்றல், சூதாட்டம் மற்றும் குழந்தைகளுடன் இணைகிறது. ஜாதகர் திறமையான புனைகதை எழுத்தாளர், நடிப்புக் கலைஞர் அல்லது கல்வியாளராக இருக்கலாம்.',te:'సహజేశుడు ఐదవ భావంలో ఉంటే సంభాషణ నైపుణ్యం సృజనాత్మకత, ఊహాజల్పన మరియు పిల్లలతో కలుస్తుంది. జాతకుడు నేర్పైన కథా రచయిత, ప్రదర్శన కళాకారుడు లేదా విద్యావేత్త కావచ్చు.',bn:'সহজেশ পঞ্চম ভাবে থাকলে যোগাযোগ দক্ষতা সৃজনশীলতা, ফাটকা ও সন্তানের সাথে মিলিত হয়। জাতক দক্ষ কথাসাহিত্য লেখক, অভিনয়শিল্পী বা শিক্ষাবিদ হতে পারে।',mr:'सहजेश पाचव्या भावात असल्यास संवाद कौशल्य सर्जनशीलता, सट्टा व संततीशी जोडते. जातक कुशल कथा-लेखक, अभिनय कलाकार किंवा शिक्षक असू शकतो.',pa:'ਸਹਜੇਸ਼ ਪੰਜਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਸੰਚਾਰ ਹੁਨਰ ਰਚਨਾਤਮਕਤਾ, ਸੱਟੇ ਅਤੇ ਸੰਤਾਨ ਨਾਲ ਜੁੜਦਾ ਹੈ। ਜਾਤਕ ਨਿਪੁੰਨ ਕਥਾ-ਲੇਖਕ, ਅਦਾਕਾਰ ਜਾਂ ਸਿੱਖਿਅਕ ਹੋ ਸਕਦਾ ਹੈ।',gu:'સહજેશ પાંચમા ભાવમાં હોય તો સંવાદ કૌશલ્ય સર્જનાત્મકતા, સટ્ટા અને સંતાન સાથે જોડાય છે. જાતક કુશળ કથા-લેખક, અભિનય કલાકાર કે શિક્ષક હોઈ શકે.'},
    6:{ta:'சஹஜேஷ் ஆறாம் பாவத்தில் இருந்தால் உடன்பிறந்தோருடன் மோதல்கள், கை அல்லது நுரையீரல் தொடர்பான ஆரோக்கிய பிரச்சினைகள் மற்றும் தொடர்பு சார்ந்த துறைகளில் போட்டியை உருவாக்குகிறது. ஜாதகர் கடுமையாகப் போராடுகிறார், சுகாதாரம் அல்லது சட்டத்தில் பணிபுரியலாம்.',te:'సహజేశుడు ఆరవ భావంలో ఉంటే సహోదరులతో ఘర్షణలు, చేయి లేదా ఊపిరితిత్తుల సంబంధ ఆరోగ్య సమస్యలు మరియు సంభాషణ-ఆధారిత రంగాలలో పోటీని సృష్టిస్తుంది. జాతకుడు గట్టిగా పోరాడతాడు, ఆరోగ్య సంరక్షణ లేదా న్యాయంలో పని చేయవచ్చు.',bn:'সহজেশ ষষ্ঠ ভাবে থাকলে ভাইবোনের সাথে দ্বন্দ্ব, হাত বা ফুসফুস সংক্রান্ত স্বাস্থ্য সমস্যা ও যোগাযোগভিত্তিক ক্ষেত্রে প্রতিযোগিতা সৃষ্টি করে। জাতক কঠোর সংগ্রাম করে এবং স্বাস্থ্যসেবা বা আইনে কাজ করতে পারে।',mr:'सहजेश सहाव्या भावात असल्यास भावंडांशी संघर्ष, हात किंवा फुफ्फुस संबंधित आरोग्य समस्या व संवाद-आधारित क्षेत्रांत स्पर्धा निर्माण करते. जातक कठोर संघर्ष करतो व आरोग्यसेवा किंवा कायद्यात काम करू शकतो.',pa:'ਸਹਜੇਸ਼ ਛੇਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਭੈਣ-ਭਰਾਵਾਂ ਨਾਲ ਟਕਰਾਅ, ਹੱਥ ਜਾਂ ਫੇਫੜੇ ਸੰਬੰਧੀ ਸਿਹਤ ਸਮੱਸਿਆਵਾਂ ਅਤੇ ਸੰਚਾਰ-ਆਧਾਰਿਤ ਖੇਤਰਾਂ ਵਿੱਚ ਮੁਕਾਬਲਾ ਪੈਦਾ ਕਰਦਾ ਹੈ। ਜਾਤਕ ਸਖ਼ਤ ਸੰਘਰਸ਼ ਕਰਦਾ ਅਤੇ ਸਿਹਤ ਸੇਵਾ ਜਾਂ ਕਾਨੂੰਨ ਵਿੱਚ ਕੰਮ ਕਰ ਸਕਦਾ ਹੈ।',gu:'સહજેશ છઠ્ઠા ભાવમાં હોય તો ભાઈ-બહેન સાથે સંઘર્ષ, હાથ કે ફેફસાં સંબંધિત આરોગ્ય સમસ્યાઓ અને સંવાદ-આધારિત ક્ષેત્રોમાં સ્પર્ધા સર્જે છે. જાતક સખત સંઘર્ષ કરે અને આરોગ્યસેવા કે કાયદામાં કામ કરી શકે.'},
    7:{ta:'சஹஜேஷ் ஏழாம் பாவத்தில் இருந்தால் தொடர்புத் திறன் மற்றும் திறமையான துணையை அளிக்கிறது. ஊடகம், வர்த்தகம் அல்லது தொழில்நுட்பத்தில் கூட்டாண்மைகள் மூலம் வணிக வெற்றி வருகிறது.',te:'సహజేశుడు ఏడవ భావంలో ఉంటే సంభాషణ శీలి మరియు నేర్పైన భాగస్వామిని ఇస్తుంది. మీడియా, వాణిజ్యం లేదా సాంకేతికతలో భాగస్వామ్యాల ద్వారా వ్యాపార విజయం వస్తుంది.',bn:'সহজেশ সপ্তম ভাবে থাকলে যোগাযোগপ্রবণ ও দক্ষ সঙ্গী দেয়। মিডিয়া, বাণিজ্য বা প্রযুক্তিতে অংশীদারিত্বের মাধ্যমে ব্যবসায়িক সাফল্য আসে।',mr:'सहजेश सातव्या भावात असल्यास संवादशील व कुशल जोडीदार देते. माध्यम, व्यापार किंवा तंत्रज्ञानातील भागीदारीतून व्यावसायिक यश येते.',pa:'ਸਹਜੇਸ਼ ਸੱਤਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਸੰਚਾਰਸ਼ੀਲ ਅਤੇ ਨਿਪੁੰਨ ਸਾਥੀ ਦਿੰਦਾ ਹੈ। ਮੀਡੀਆ, ਵਪਾਰ ਜਾਂ ਤਕਨਾਲੋਜੀ ਵਿੱਚ ਭਾਈਵਾਲੀਆਂ ਰਾਹੀਂ ਵਪਾਰਕ ਸਫਲਤਾ ਆਉਂਦੀ ਹੈ।',gu:'સહજેશ સાતમા ભાવમાં હોય તો સંવાદશીલ અને કુશળ સાથી આપે છે. મીડિયા, વેપાર કે ટેકનોલોજીમાં ભાગીદારી દ્વારા વ્યાવસાયિક સફળતા આવે છે.'},
    8:{ta:'சஹஜேஷ் எட்டாம் பாவத்தில் இருந்தால் உடன்பிறந்தோர் தொடர்பான திடீர் நிகழ்வுகள், ரகசிய தொடர்புகள், ஆராய்ச்சி மற்றும் மறைவான அறிவில் ஆர்வத்தை உருவாக்குகிறது. ஜாதகர் நெகிழ்திறன் உள்ளவர் ஆனால் எதிர்பாராத பின்னடைவுகளை எதிர்கொள்ளலாம்.',te:'సహజేశుడు ఎనిమిదవ భావంలో ఉంటే సహోదర సంబంధ ఆకస్మిక సంఘటనలు, రహస్య సంభాషణలు, పరిశోధన మరియు గుప్త జ్ఞానంలో ఆసక్తిని సృష్టిస్తుంది. జాతకుడు దృఢమైనవాడు కానీ ఊహించని ఎదురుదెబ్బలను ఎదుర్కోవచ్చు.',bn:'সহজেশ অষ্টম ভাবে থাকলে ভাইবোন সংক্রান্ত আকস্মিক ঘটনা, গোপন যোগাযোগ, গবেষণা ও গুপ্ত জ্ঞানে আগ্রহ সৃষ্টি করে। জাতক স্থিতিস্থাপক কিন্তু অপ্রত্যাশিত বাধার সম্মুখীন হতে পারে।',mr:'सहजेश आठव्या भावात असल्यास भावंड संबंधित आकस्मिक घटना, गुप्त संवाद, संशोधन व गुप्त ज्ञानात रुची निर्माण करते. जातक लवचिक असतो पण अनपेक्षित अपयशांना सामोरा जाऊ शकतो.',pa:'ਸਹਜੇਸ਼ ਅੱਠਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਭੈਣ-ਭਰਾ ਸੰਬੰਧੀ ਅਚਾਨਕ ਘਟਨਾਵਾਂ, ਗੁਪਤ ਸੰਚਾਰ, ਖੋਜ ਅਤੇ ਗੁਪਤ ਗਿਆਨ ਵਿੱਚ ਰੁਚੀ ਪੈਦਾ ਕਰਦਾ ਹੈ। ਜਾਤਕ ਲਚਕਦਾਰ ਹੁੰਦਾ ਪਰ ਅਣਕਿਆਸੇ ਝਟਕਿਆਂ ਦਾ ਸਾਹਮਣਾ ਕਰ ਸਕਦਾ ਹੈ।',gu:'સહજેશ આઠમા ભાવમાં હોય તો ભાઈ-બહેન સંબંધિત અચાનક ઘટનાઓ, ગુપ્ત સંવાદ, સંશોધન અને ગુપ્ત જ્ઞાનમાં રસ સર્જે છે. જાતક સ્થિતિસ્થાપક હોય પણ અણધાર્યા આંચકાનો સામનો કરી શકે.'},
    9:{ta:'சஹஜேஷ் ஒன்பதாம் பாவத்தில் இருந்தால் தைரியம் தத்துவம், மதம் மற்றும் நீண்ட பயணங்களுக்குள் வருகிறது. ஜாதகர் விரிவாகப் பயணிக்கிறார், ஆன்மிகம் பற்றி எழுதுகிறார் அல்லது மத தொடர்பாளராகிறார்.',te:'సహజేశుడు తొమ్మిదవ భావంలో ఉంటే ధైర్యం తత్వశాస్త్రం, మతం మరియు దీర్ఘ ప్రయాణాలలోకి వస్తుంది. జాతకుడు విస్తృతంగా ప్రయాణిస్తాడు, ఆధ్యాత్మికత గురించి రాస్తాడు లేదా మత సంభాషకుడు అవుతాడు.',bn:'সহজেশ নবম ভাবে থাকলে সাহস দর্শন, ধর্ম ও দীর্ঘ ভ্রমণে আসে। জাতক ব্যাপকভাবে ভ্রমণ করে, আধ্যাত্মিকতা নিয়ে লেখে বা ধর্মীয় যোগাযোগকারী হয়।',mr:'सहजेश नवव्या भावात असल्यास धैर्य तत्त्वज्ञान, धर्म व दीर्घ प्रवासात येते. जातक व्यापक प्रवास करतो, आध्यात्मिकतेवर लिहितो किंवा धार्मिक संवादक होतो.',pa:'ਸਹਜੇਸ਼ ਨੌਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਹੌਸਲਾ ਦਰਸ਼ਨ, ਧਰਮ ਅਤੇ ਲੰਬੇ ਸਫ਼ਰਾਂ ਵਿੱਚ ਆਉਂਦਾ ਹੈ। ਜਾਤਕ ਵਿਆਪਕ ਸਫ਼ਰ ਕਰਦਾ, ਅਧਿਆਤਮਕਤਾ ਬਾਰੇ ਲਿਖਦਾ ਜਾਂ ਧਾਰਮਿਕ ਸੰਚਾਰਕ ਬਣਦਾ ਹੈ।',gu:'સહજેશ નવમા ભાવમાં હોય તો હિંમત દર્શન, ધર્મ અને લાંબી મુસાફરીમાં આવે છે. જાતક વ્યાપક મુસાફરી કરે, આધ્યાત્મિકતા વિશે લખે કે ધાર્મિક સંવાદક બને છે.'},
    10:{ta:'சஹஜேஷ் பத்தாம் பாவத்தில் இருந்தால் ஊடகம், தொடர்பு, எழுத்து அல்லது தொழில்நுட்பத்தில் தொழில் உருவாகிறது. ஜாதகர் தைரியமான தொழில்முறை செயல்களால் பொது அங்கீகாரத்தைப் பெறுகிறார்.',te:'సహజేశుడు పదవ భావంలో ఉంటే మీడియా, సంభాషణ, రచన లేదా సాంకేతికతలో వృత్తి ఏర్పడుతుంది. జాతకుడు ధైర్యవంతమైన వృత్తిపరమైన చర్యల ద్వారా ప్రజా గుర్తింపును పొందుతాడు.',bn:'সহজেশ দশম ভাবে থাকলে মিডিয়া, যোগাযোগ, লেখা বা প্রযুক্তিতে কর্মজীবন গড়ে। জাতক সাহসী পেশাগত কর্মের মাধ্যমে জনস্বীকৃতি অর্জন করে।',mr:'सहजेश दहाव्या भावात असल्यास माध्यम, संवाद, लेखन किंवा तंत्रज्ञानात करिअर घडते. जातक धाडसी व्यावसायिक कृतींतून जनमान्यता मिळवतो.',pa:'ਸਹਜੇਸ਼ ਦਸਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਮੀਡੀਆ, ਸੰਚਾਰ, ਲਿਖਤ ਜਾਂ ਤਕਨਾਲੋਜੀ ਵਿੱਚ ਕਰੀਅਰ ਬਣਦਾ ਹੈ। ਜਾਤਕ ਬਹਾਦਰ ਪੇਸ਼ੇਵਰ ਕੰਮਾਂ ਰਾਹੀਂ ਜਨਤਕ ਮਾਨਤਾ ਪ੍ਰਾਪਤ ਕਰਦਾ ਹੈ।',gu:'સહજેશ દશમા ભાવમાં હોય તો મીડિયા, સંવાદ, લેખન કે ટેકનોલોજીમાં કારકિર્દી બને છે. જાતક હિંમતવાન વ્યાવસાયિક કાર્યો દ્વારા જનમાન્યતા મેળવે છે.'},
    11:{ta:'சஹஜேஷ் பதினொன்றாம் பாவத்தில் இருந்தால் உடன்பிறந்தோர், தொடர்பு மற்றும் வலைப்பின்னல் மூலம் லாபங்கள் வருகின்றன. ஜாதகர் ஊடக முயற்சிகள், சமூக குழுக்கள் மற்றும் கூட்டு தொடர்புகளின் மூலம் இலக்குகளை அடைகிறார்.',te:'సహజేశుడు పదకొండవ భావంలో ఉంటే సహోదరులు, సంభాషణ మరియు నెట్‌వర్కింగ్ ద్వారా లాభాలు వస్తాయి. జాతకుడు మీడియా వెంచర్లు, సామాజిక సమూహాలు మరియు సమూహ సంభాషణల ద్వారా లక్ష్యాలను సాధిస్తాడు.',bn:'সহজেশ একাদশ ভাবে থাকলে ভাইবোন, যোগাযোগ ও নেটওয়ার্কিংয়ের মাধ্যমে লাভ আসে। জাতক মিডিয়া উদ্যোগ, সামাজিক দল ও দলগত যোগাযোগের মাধ্যমে লক্ষ্য অর্জন করে।',mr:'सहजेश अकराव्या भावात असल्यास भावंडे, संवाद व नेटवर्किंगमधून लाभ येतात. जातक माध्यम उपक्रम, सामाजिक गट व सामूहिक संवादातून ध्येय गाठतो.',pa:'ਸਹਜੇਸ਼ ਗਿਆਰਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਭੈਣ-ਭਰਾ, ਸੰਚਾਰ ਅਤੇ ਨੈੱਟਵਰਕਿੰਗ ਰਾਹੀਂ ਲਾਭ ਆਉਂਦੇ ਹਨ। ਜਾਤਕ ਮੀਡੀਆ ਉੱਦਮਾਂ, ਸਮਾਜਿਕ ਸਮੂਹਾਂ ਅਤੇ ਸਮੂਹਿਕ ਸੰਚਾਰ ਰਾਹੀਂ ਟੀਚੇ ਪ੍ਰਾਪਤ ਕਰਦਾ ਹੈ।',gu:'સહજેશ અગિયારમા ભાવમાં હોય તો ભાઈ-બહેન, સંવાદ અને નેટવર્કિંગ દ્વારા લાભ આવે છે. જાતક મીડિયા સાહસો, સામાજિક જૂથો અને સામૂહિક સંવાદ દ્વારા લક્ષ્ય મેળવે છે.'},
    12:{ta:'சஹஜேஷ் பன்னிரண்டாம் பாவத்தில் இருந்தால் உடன்பிறந்தோரிடமிருந்து தூரம், பயணங்களுக்கான செலவுகள் மற்றும் ஆன்மிகம் அல்லது வெளிநாட்டு விஷயங்கள் பற்றிய தொடர்பை ஏற்படுத்துகிறது. ஜாதகர் ரகசிய அல்லது ஆன்மிக விஷயங்கள் பற்றி எழுதலாம்.',te:'సహజేశుడు పన్నెండవ భావంలో ఉంటే సహోదరుల నుండి దూరం, ప్రయాణాలపై ఖర్చులు మరియు ఆధ్యాత్మికత లేదా విదేశీ విషయాల గురించి సంభాషణను సృష్టిస్తుంది. జాతకుడు రహస్య లేదా ఆధ్యాత్మిక విషయాల గురించి రాయవచ్చు.',bn:'সহজেশ দ্বাদশ ভাবে থাকলে ভাইবোন থেকে দূরত্ব, ভ্রমণে ব্যয় ও আধ্যাত্মিকতা বা বিদেশি বিষয় নিয়ে যোগাযোগ সৃষ্টি করে। জাতক গোপন বা আধ্যাত্মিক বিষয়ে লিখতে পারে।',mr:'सहजेश बाराव्या भावात असल्यास भावंडांपासून अंतर, प्रवासावर खर्च व आध्यात्मिकता किंवा परदेशी विषयांवर संवाद निर्माण करते. जातक गुप्त किंवा आध्यात्मिक विषयांवर लिहू शकतो.',pa:'ਸਹਜੇਸ਼ ਬਾਰ੍ਹਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਭੈਣ-ਭਰਾਵਾਂ ਤੋਂ ਦੂਰੀ, ਸਫ਼ਰਾਂ ਤੇ ਖਰਚ ਅਤੇ ਅਧਿਆਤਮਕਤਾ ਜਾਂ ਵਿਦੇਸ਼ੀ ਵਿਸ਼ਿਆਂ ਬਾਰੇ ਸੰਚਾਰ ਪੈਦਾ ਕਰਦਾ ਹੈ। ਜਾਤਕ ਗੁਪਤ ਜਾਂ ਅਧਿਆਤਮਕ ਵਿਸ਼ਿਆਂ ਤੇ ਲਿਖ ਸਕਦਾ ਹੈ।',gu:'સહજેશ બારમા ભાવમાં હોય તો ભાઈ-બહેનથી અંતર, મુસાફરી પર ખર્ચ અને આધ્યાત્મિકતા કે વિદેશી વિષયો પર સંવાદ સર્જે છે. જાતક ગુપ્ત કે આધ્યાત્મિક વિષયો પર લખી શકે.'},
  },
  4: {
    1:{ta:'மாத்ரேஷ் முதலாம் பாவத்தில் இருந்தால் ஜாதகர் உணர்வுபூர்வமாக வெளிப்படுத்தும், வீட்டுடன் பிணைந்த மற்றும் தாயுடன் ஆழமாக இணைந்தவராகிறார். ஜாதகர் தன் ஆளுமையில் குடும்பத்தின் ஆற்றலைச் சுமக்கிறார்.',te:'మాత్రేశుడు మొదటి భావంలో ఉంటే జాతకుడు భావోద్వేగపరంగా వ్యక్తీకరించేవాడు, ఇంటికి అనుబంధమైనవాడు మరియు తల్లితో లోతుగా ముడిపడినవాడు అవుతాడు. జాతకుడు తన వ్యక్తిత్వంలో కుటుంబ శక్తిని మోస్తాడు.',bn:'মাত্রেশ প্রথম ভাবে থাকলে জাতক আবেগপ্রবণ, বাড়ির প্রতি আসক্ত ও মাতার সাথে গভীরভাবে যুক্ত হয়। জাতক তার ব্যক্তিত্বে পরিবারের শক্তি বহন করে।',mr:'मातृश पहिल्या भावात असल्यास जातक भावनिकदृष्ट्या अभिव्यक्तिशील, घराशी जोडलेला व मातेशी खोलवर संबंधित होतो. जातक आपल्या व्यक्तिमत्त्वात कौटुंबिक ऊर्जा वाहतो.',pa:'ਮਾਤ੍ਰੇਸ਼ ਪਹਿਲੇ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਜਾਤਕ ਭਾਵਨਾਤਮਕ ਤੌਰ ਤੇ ਪ੍ਰਗਟਾਵੇ ਵਾਲਾ, ਘਰ ਨਾਲ ਜੁੜਿਆ ਅਤੇ ਮਾਂ ਨਾਲ ਡੂੰਘਾ ਸੰਬੰਧਿਤ ਹੁੰਦਾ ਹੈ। ਜਾਤਕ ਆਪਣੀ ਸ਼ਖਸੀਅਤ ਵਿੱਚ ਪਰਿਵਾਰਕ ਊਰਜਾ ਲੈ ਕੇ ਚੱਲਦਾ ਹੈ।',gu:'માતૃશ પ્રથમ ભાવમાં હોય તો જાતક ભાવનાત્મક રીતે અભિવ્યક્તિશીલ, ઘર સાથે જોડાયેલ અને માતા સાથે ઊંડે સંકળાયેલ હોય છે. જાતક પોતાના વ્યક્તિત્વમાં કૌટુંબિક ઊર્જા વહન કરે છે.'},
    2:{ta:'மாத்ரேஷ் இரண்டாம் பாவத்தில் இருந்தால் குடும்ப செல்வம், மூதாதையர் சொத்து மற்றும் நிலம் கிடைக்கிறது. ஜாதகர் அசையாச் சொத்து மூலம் செல்வத்தைச் சேர்க்கிறார், குடும்ப மரபுகளால் போஷிக்கப்படுகிறார்.',te:'మాత్రేశుడు రెండవ భావంలో ఉంటే కుటుంబ సంపద, పూర్వీకుల ఆస్తి మరియు భూమి లభిస్తాయి. జాతకుడు స్థిరాస్తి ద్వారా సంపదను సంపాదిస్తాడు, కుటుంబ సంప్రదాయాలచే పోషించబడతాడు.',bn:'মাত্রেশ দ্বিতীয় ভাবে থাকলে পারিবারিক সম্পদ, পৈতৃক সম্পত্তি ও জমি লাভ হয়। জাতক স্থাবর সম্পত্তির মাধ্যমে সম্পদ সঞ্চয় করে ও পারিবারিক ঐতিহ্যে পুষ্ট হয়।',mr:'मातृश दुसऱ्या भावात असल्यास कौटुंबिक संपत्ती, वडिलोपार्जित मालमत्ता व जमीन मिळते. जातक स्थावर मालमत्तेतून संपत्ती संचय करतो व कौटुंबिक परंपरांनी पोषित होतो.',pa:'ਮਾਤ੍ਰੇਸ਼ ਦੂਜੇ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਪਰਿਵਾਰਕ ਦੌਲਤ, ਜੱਦੀ ਜਾਇਦਾਦ ਅਤੇ ਜ਼ਮੀਨ ਮਿਲਦੀ ਹੈ। ਜਾਤਕ ਅਚੱਲ ਜਾਇਦਾਦ ਰਾਹੀਂ ਦੌਲਤ ਸੰਚਯ ਕਰਦਾ ਅਤੇ ਪਰਿਵਾਰਕ ਪਰੰਪਰਾਵਾਂ ਨਾਲ ਪਲਦਾ ਹੈ।',gu:'માતૃશ બીજા ભાવમાં હોય તો કૌટુંબિક સંપત્તિ, પૈતૃક મિલકત અને જમીન મળે છે. જાતક સ્થાવર મિલકત દ્વારા સંપત્તિ સંચય કરે અને કૌટુંબિક પરંપરાઓથી પોષાય છે.'},
    3:{ta:'மாத்ரேஷ் மூன்றாம் பாவத்தில் இருந்தால் வீட்டு விவகாரங்கள் மற்றும் குறுகிய பயணங்களில் தைரியம் வருகிறது. ஜாதகர் சொத்து-தொடர்பு, வீட்டு மேம்பாட்டில் பணிபுரியலாம் அல்லது ஒரு உடன்பிறந்தவர் சொத்துடன் நெருக்கமாக இணைந்திருக்கலாம்.',te:'మాత్రేశుడు మూడవ భావంలో ఉంటే గృహ వ్యవహారాలు మరియు చిన్న ప్రయాణాలలో ధైర్యం వస్తుంది. జాతకుడు ఆస్తి-సంభాషణ, గృహ మెరుగుదలలో పని చేయవచ్చు లేదా ఒక సహోదరుడు ఆస్తితో దగ్గరగా ముడిపడి ఉండవచ్చు.',bn:'মাত্রেশ তৃতীয় ভাবে থাকলে গৃহবিষয় ও স্বল্প ভ্রমণে সাহস আসে। জাতক সম্পত্তি-যোগাযোগ, গৃহ উন্নয়নে কাজ করতে পারে বা কোনো ভাইবোন সম্পত্তির সাথে ঘনিষ্ঠভাবে যুক্ত থাকতে পারে।',mr:'मातृश तिसऱ्या भावात असल्यास घरगुती व्यवहार व लहान प्रवासात धैर्य येते. जातक मालमत्ता-संवाद, गृह सुधारणेत काम करू शकतो किंवा एखादे भावंड मालमत्तेशी जवळून जोडलेले असू शकते.',pa:'ਮਾਤ੍ਰੇਸ਼ ਤੀਜੇ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਘਰੇਲੂ ਮਾਮਲਿਆਂ ਅਤੇ ਛੋਟੇ ਸਫ਼ਰਾਂ ਵਿੱਚ ਹੌਸਲਾ ਆਉਂਦਾ ਹੈ। ਜਾਤਕ ਜਾਇਦਾਦ-ਸੰਚਾਰ, ਘਰ ਸੁਧਾਰ ਵਿੱਚ ਕੰਮ ਕਰ ਸਕਦਾ ਜਾਂ ਕੋਈ ਭੈਣ-ਭਰਾ ਜਾਇਦਾਦ ਨਾਲ ਨੇੜਿਓਂ ਜੁੜਿਆ ਹੋ ਸਕਦਾ ਹੈ।',gu:'માતૃશ ત્રીજા ભાવમાં હોય તો ઘરેલું બાબતો અને ટૂંકી મુસાફરીમાં હિંમત આવે છે. જાતક મિલકત-સંવાદ, ઘર સુધારણામાં કામ કરી શકે અથવા કોઈ ભાઈ-બહેન મિલકત સાથે નજીકથી જોડાયેલ હોઈ શકે.'},
    4:{ta:'மாத்ரேஷ் தன் சொந்த பாவத்தில் இருப்பது சிறந்தது — வீட்டு மகிழ்ச்சி, அன்பான தாய், அழகிய வீடு, வாகனங்கள் மற்றும் ஆழமான உணர்வு நிறைவை அளிக்கிறது. ஜாதகர் வேரூன்றியவராகவும் உணர்வு ரீதியில் நிலையானவராகவும் இருக்கிறார்.',te:'మాత్రేశుడు తన స్వంత భావంలో ఉండటం అద్భుతం — గృహ సౌఖ్యం, ప్రేమమయ తల్లి, అందమైన ఇల్లు, వాహనాలు మరియు లోతైన భావోద్వేగ సంతృప్తిని ఇస్తుంది. జాతకుడు స్థిరమైనవాడు మరియు భావోద్వేగపరంగా సమతుల్యుడు.',bn:'মাত্রেশ নিজ ভাবে থাকা উৎকৃষ্ট — গৃহসুখ, স্নেহময়ী মাতা, সুন্দর বাড়ি, যানবাহন ও গভীর আবেগীয় তৃপ্তি দেয়। জাতক প্রোথিত ও আবেগীয়ভাবে স্থিতিশীল হয়।',mr:'मातृश स्वतःच्या भावात असणे उत्कृष्ट — गृहसुख, प्रेमळ माता, सुंदर घर, वाहने व खोल भावनिक समाधान देते. जातक स्थिर व भावनिकदृष्ट्या संतुलित असतो.',pa:'ਮਾਤ੍ਰੇਸ਼ ਆਪਣੇ ਭਾਵ ਵਿੱਚ ਹੋਣਾ ਵਧੀਆ — ਘਰੇਲੂ ਖੁਸ਼ੀ, ਪਿਆਰੀ ਮਾਂ, ਸੁੰਦਰ ਘਰ, ਵਾਹਨ ਅਤੇ ਡੂੰਘੀ ਭਾਵਨਾਤਮਕ ਸੰਤੁਸ਼ਟੀ ਦਿੰਦਾ ਹੈ। ਜਾਤਕ ਸਥਿਰ ਅਤੇ ਭਾਵਨਾਤਮਕ ਤੌਰ ਤੇ ਸੰਤੁਲਿਤ ਹੁੰਦਾ ਹੈ।',gu:'માતૃશ પોતાના ભાવમાં હોવું ઉત્કૃષ્ટ — ગૃહસુખ, પ્રેમાળ માતા, સુંદર ઘર, વાહનો અને ઊંડો ભાવનાત્મક સંતોષ આપે છે. જાતક સ્થિર અને ભાવનાત્મક રીતે સંતુલિત હોય છે.'},
    5:{ta:'மாத்ரேஷ் ஐந்தாம் பாவத்தில் இருந்தால் குழந்தைகள் மற்றும் வீட்டு அடிப்படையிலான படைப்பு நடவடிக்கைகள் மூலம் மகிழ்ச்சி வருகிறது. ஜாதகர் கற்பித்தல், கலைகள் மற்றும் குழந்தைகளுடன் உறவில் ஆழமான உணர்வு நிறைவைக் காண்கிறார்.',te:'మాత్రేశుడు ఐదవ భావంలో ఉంటే పిల్లలు మరియు గృహ-ఆధారిత సృజనాత్మక కార్యకలాపాల ద్వారా సంతోషం వస్తుంది. జాతకుడు బోధన, కళలు మరియు పిల్లలతో సంబంధంలో లోతైన భావోద్వేగ సంతృప్తిని పొందుతాడు.',bn:'মাত্রেশ পঞ্চম ভাবে থাকলে সন্তান ও গৃহভিত্তিক সৃজনশীল কার্যক্রমের মাধ্যমে সুখ আসে। জাতক শিক্ষকতা, কলা ও সন্তানের সাথে সম্পর্কে গভীর আবেগীয় তৃপ্তি পায়।',mr:'मातृश पाचव्या भावात असल्यास संतती व घर-आधारित सर्जनशील कृतींतून सुख मिळते. जातक अध्यापन, कला व संततीशी नात्यात खोल भावनिक समाधान पाहतो.',pa:'ਮਾਤ੍ਰੇਸ਼ ਪੰਜਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਸੰਤਾਨ ਅਤੇ ਘਰ-ਆਧਾਰਿਤ ਰਚਨਾਤਮਕ ਗਤੀਵਿਧੀਆਂ ਰਾਹੀਂ ਖੁਸ਼ੀ ਆਉਂਦੀ ਹੈ। ਜਾਤਕ ਅਧਿਆਪਨ, ਕਲਾਵਾਂ ਅਤੇ ਸੰਤਾਨ ਨਾਲ ਰਿਸ਼ਤੇ ਵਿੱਚ ਡੂੰਘੀ ਭਾਵਨਾਤਮਕ ਸੰਤੁਸ਼ਟੀ ਲੱਭਦਾ ਹੈ।',gu:'માતૃશ પાંચમા ભાવમાં હોય તો સંતાન અને ઘર-આધારિત સર્જનાત્મક પ્રવૃત્તિઓ દ્વારા સુખ આવે છે. જાતક અધ્યાપન, કલા અને સંતાન સાથે સંબંધમાં ઊંડો ભાવનાત્મક સંતોષ મેળવે છે.'},
    6:{ta:'மாத்ரேஷ் ஆறாம் பாவத்தில் இருந்தால் தாயின் ஆரோக்கியம், வீட்டு தகராறுகள் அல்லது சொத்து இழப்பு தொடர்பான பிரச்சினைகளை உருவாக்கலாம். இருப்பினும், ஜாதகர் சுகாதாரம், சொத்து பராமரிப்பு அல்லது வீட்டுச் சேவைகளில் பணிபுரியலாம்.',te:'మాత్రేశుడు ఆరవ భావంలో ఉంటే తల్లి ఆరోగ్యం, గృహ వివాదాలు లేదా ఆస్తి నష్టం సంబంధ సమస్యలను సృష్టించవచ్చు. అయితే, జాతకుడు ఆరోగ్య సంరక్షణ, ఆస్తి నిర్వహణ లేదా గృహ సేవలలో పని చేయవచ్చు.',bn:'মাত্রেশ ষষ্ঠ ভাবে থাকলে মাতার স্বাস্থ্য, গৃহবিরোধ বা সম্পত্তি ক্ষতি সংক্রান্ত সমস্যা সৃষ্টি করতে পারে। তবে জাতক স্বাস্থ্যসেবা, সম্পত্তি রক্ষণাবেক্ষণ বা গৃহসেবায় নিযুক্ত হতে পারে।',mr:'मातृश सहाव्या भावात असल्यास मातेच्या आरोग्याच्या, घरगुती वादांच्या किंवा मालमत्ता हानीच्या समस्या निर्माण होऊ शकतात. तथापि, जातक आरोग्यसेवा, मालमत्ता देखभाल किंवा घरगुती सेवांत काम करू शकतो.',pa:'ਮਾਤ੍ਰੇਸ਼ ਛੇਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਮਾਂ ਦੀ ਸਿਹਤ, ਘਰੇਲੂ ਝਗੜੇ ਜਾਂ ਜਾਇਦਾਦ ਹਾਨੀ ਸੰਬੰਧੀ ਸਮੱਸਿਆਵਾਂ ਪੈਦਾ ਕਰ ਸਕਦਾ ਹੈ। ਫਿਰ ਵੀ, ਜਾਤਕ ਸਿਹਤ ਸੇਵਾ, ਜਾਇਦਾਦ ਦੇਖਭਾਲ ਜਾਂ ਘਰੇਲੂ ਸੇਵਾਵਾਂ ਵਿੱਚ ਕੰਮ ਕਰ ਸਕਦਾ ਹੈ।',gu:'માતૃશ છઠ્ઠા ભાવમાં હોય તો માતાનું આરોગ્ય, ઘરેલું વિવાદ કે મિલકત હાનિ સંબંધિત સમસ્યાઓ સર્જી શકે. તેમ છતાં, જાતક આરોગ્યસેવા, મિલકત જાળવણી કે ઘરેલું સેવાઓમાં કામ કરી શકે.'},
    7:{ta:'மாத்ரேஷ் ஏழாம் பாவத்தில் இருந்தால் திருமணத்தின் மூலம் வீட்டு மகிழ்ச்சி வருகிறது. ஜாதகர் உணர்வு பாதுகாப்பு மற்றும் வசதியான வீட்டு வாழ்க்கையை வழங்கும் துணையைத் தேடுகிறார். திருமணத்தின் மூலம் வெளிநாட்டு குடியேற்றம் சாத்தியம்.',te:'మాత్రేశుడు ఏడవ భావంలో ఉంటే వివాహం ద్వారా గృహ సౌఖ్యం వస్తుంది. జాతకుడు భావోద్వేగ భద్రత మరియు సౌకర్యవంతమైన గృహ జీవితాన్ని అందించే భాగస్వామిని కోరుకుంటాడు. వివాహం ద్వారా విదేశీ స్థిరనివాసం సాధ్యం.',bn:'মাত্রেশ সপ্তম ভাবে থাকলে বিবাহের মাধ্যমে গৃহসুখ আসে। জাতক এমন সঙ্গী খোঁজে যে আবেগীয় নিরাপত্তা ও আরামদায়ক গৃহজীবন প্রদান করে। বিবাহের মাধ্যমে বিদেশে বসতি সম্ভব।',mr:'मातृश सातव्या भावात असल्यास विवाहाद्वारे गृहसुख मिळते. जातक भावनिक सुरक्षा व आरामदायी गृहजीवन देणारा जोडीदार शोधतो. विवाहाद्वारे परदेश वास शक्य.',pa:'ਮਾਤ੍ਰੇਸ਼ ਸੱਤਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਵਿਆਹ ਰਾਹੀਂ ਘਰੇਲੂ ਖੁਸ਼ੀ ਆਉਂਦੀ ਹੈ। ਜਾਤਕ ਭਾਵਨਾਤਮਕ ਸੁਰੱਖਿਆ ਅਤੇ ਆਰਾਮਦਾਇਕ ਘਰੇਲੂ ਜੀਵਨ ਦੇਣ ਵਾਲਾ ਸਾਥੀ ਲੱਭਦਾ ਹੈ। ਵਿਆਹ ਰਾਹੀਂ ਵਿਦੇਸ਼ੀ ਵਸੇਬਾ ਸੰਭਵ।',gu:'માતૃશ સાતમા ભાવમાં હોય તો લગ્ન દ્વારા ગૃહસુખ આવે છે. જાતક ભાવનાત્મક સુરક્ષા અને આરામદાયક ગૃહજીવન આપતો સાથી શોધે છે. લગ્ન દ્વારા વિદેશ વસવાટ શક્ય.'},
    8:{ta:'மாத்ரேஷ் எட்டாம் பாவத்தில் இருந்தால் வீட்டு வாழ்க்கையில் திடீர் மாற்றங்கள், தாயின் ஆரோக்கிய சவால்கள் மற்றும் மறைவான சொத்தை உருவாக்குகிறது. ஜாதகருக்கு நிலம் வாரிசாக வரலாம் ஆனால் குடும்ப நிலையின்மை அல்லது மூதாதையர் ரகசியங்களை எதிர்கொள்ளலாம்.',te:'మాత్రేశుడు ఎనిమిదవ భావంలో ఉంటే గృహ జీవితంలో ఆకస్మిక మార్పులు, తల్లి ఆరోగ్య సవాళ్లు మరియు గుప్త ఆస్తిని సృష్టిస్తుంది. జాతకుడికి భూమి వారసత్వంగా రావచ్చు కానీ కుటుంబ అస్థిరత లేదా పూర్వీకుల రహస్యాలను ఎదుర్కోవచ్చు.',bn:'মাত্রেশ অষ্টম ভাবে থাকলে গৃহজীবনে আকস্মিক পরিবর্তন, মাতার স্বাস্থ্য চ্যালেঞ্জ ও গুপ্ত সম্পত্তি সৃষ্টি করে। জাতক জমি উত্তরাধিকারসূত্রে পেতে পারে কিন্তু পারিবারিক অস্থিরতা বা পৈতৃক রহস্যের সম্মুখীন হতে পারে।',mr:'मातृश आठव्या भावात असल्यास गृहजीवनात आकस्मिक बदल, मातेच्या आरोग्य आव्हाने व गुप्त मालमत्ता निर्माण करते. जातकाला जमीन वारसाहक्काने मिळू शकते पण कौटुंबिक अस्थिरता किंवा वडिलोपार्जित रहस्यांना सामोरे जावे लागू शकते.',pa:'ਮਾਤ੍ਰੇਸ਼ ਅੱਠਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਘਰੇਲੂ ਜੀਵਨ ਵਿੱਚ ਅਚਾਨਕ ਬਦਲਾਅ, ਮਾਂ ਦੀ ਸਿਹਤ ਚੁਣੌਤੀਆਂ ਅਤੇ ਗੁਪਤ ਜਾਇਦਾਦ ਪੈਦਾ ਕਰਦਾ ਹੈ। ਜਾਤਕ ਨੂੰ ਜ਼ਮੀਨ ਵਿਰਾਸਤ ਵਿੱਚ ਮਿਲ ਸਕਦੀ ਪਰ ਪਰਿਵਾਰਕ ਅਸਥਿਰਤਾ ਜਾਂ ਜੱਦੀ ਰਾਜ਼ਾਂ ਦਾ ਸਾਹਮਣਾ ਕਰ ਸਕਦਾ ਹੈ।',gu:'માતૃશ આઠમા ભાવમાં હોય તો ગૃહજીવનમાં અચાનક ફેરફારો, માતાના આરોગ્ય પડકારો અને ગુપ્ત મિલકત સર્જે છે. જાતકને જમીન વારસામાં મળી શકે પણ કૌટુંબિક અસ્થિરતા કે પૈતૃક રહસ્યોનો સામનો કરી શકે.'},
    9:{ta:'மாத்ரேஷ் ஒன்பதாம் பாவத்தில் இருந்தால் ஆன்மிக அல்லது உயர் கல்வி பெற்ற தாய் அமைகிறது, ஜாதகர் மதம், தத்துவம் மற்றும் நீண்ட தீர்த்த யாத்திரைகள் மூலம் உணர்வு அமைதியைக் காண்கிறார். வெளிநாட்டில் மூதாதையர் நிலம் சாத்தியம்.',te:'మాత్రేశుడు తొమ్మిదవ భావంలో ఉంటే ఆధ్యాత్మిక లేదా ఉన్నత విద్యావంతమైన తల్లి ఏర్పడుతుంది, జాతకుడు మతం, తత్వశాస్త్రం మరియు దీర్ఘ తీర్థయాత్రల ద్వారా భావోద్వేగ శాంతిని పొందుతాడు. విదేశాలలో పూర్వీకుల భూమి సాధ్యం.',bn:'মাত্রেশ নবম ভাবে থাকলে আধ্যাত্মিক বা উচ্চশিক্ষিত মাতা হয়, জাতক ধর্ম, দর্শন ও দীর্ঘ তীর্থযাত্রার মাধ্যমে আবেগীয় শান্তি পায়। বিদেশে পৈতৃক জমি সম্ভব।',mr:'मातृश नवव्या भावात असल्यास आध्यात्मिक किंवा उच्चशिक्षित माता असते, जातक धर्म, तत्त्वज्ञान व दीर्घ तीर्थयात्रांतून भावनिक शांती पाहतो. परदेशात वडिलोपार्जित जमीन शक्य.',pa:'ਮਾਤ੍ਰੇਸ਼ ਨੌਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਅਧਿਆਤਮਕ ਜਾਂ ਉੱਚ ਸਿੱਖਿਅਤ ਮਾਂ ਹੁੰਦੀ ਹੈ, ਜਾਤਕ ਧਰਮ, ਦਰਸ਼ਨ ਅਤੇ ਲੰਬੀਆਂ ਤੀਰਥ ਯਾਤਰਾਵਾਂ ਰਾਹੀਂ ਭਾਵਨਾਤਮਕ ਸ਼ਾਂਤੀ ਲੱਭਦਾ ਹੈ। ਵਿਦੇਸ਼ ਵਿੱਚ ਜੱਦੀ ਜ਼ਮੀਨ ਸੰਭਵ।',gu:'માતૃશ નવમા ભાવમાં હોય તો આધ્યાત્મિક કે ઉચ્ચ શિક્ષિત માતા હોય છે, જાતક ધર્મ, દર્શન અને લાંબી તીર્થયાત્રા દ્વારા ભાવનાત્મક શાંતિ મેળવે છે. વિદેશમાં પૈતૃક જમીન શક્ય.'},
    10:{ta:'மாத்ரேஷ் பத்தாம் பாவத்தில் இருந்தால் தொழிலுக்கும் வீட்டுக்கும் இடையே வலுவான தொடர்பை உருவாக்குகிறது. ஜாதகர் அசையாச் சொத்து, குடும்ப வணிகம் அல்லது வீட்டிலிருந்து பணிபுரிகிறார். தொழிலில் தாயின் தாக்கம் குறிப்பிடத்தக்கது.',te:'మాత్రేశుడు పదవ భావంలో ఉంటే వృత్తికి మరియు ఇంటికి మధ్య బలమైన సంబంధాన్ని సృష్టిస్తుంది. జాతకుడు స్థిరాస్తి, కుటుంబ వ్యాపారం లేదా ఇంటి నుండి పని చేస్తాడు. వృత్తిపై తల్లి ప్రభావం గణనీయం.',bn:'মাত্রেশ দশম ভাবে থাকলে কর্মজীবন ও বাড়ির মধ্যে দৃঢ় সংযোগ সৃষ্টি করে। জাতক স্থাবর সম্পত্তি, পারিবারিক ব্যবসা বা বাড়ি থেকে কাজ করে। পেশায় মাতার প্রভাব উল্লেখযোগ্য।',mr:'मातृश दहाव्या भावात असल्यास करिअर व घर यांच्यात मजबूत संबंध निर्माण करते. जातक स्थावर मालमत्ता, कौटुंबिक व्यवसाय किंवा घरून काम करतो. व्यवसायावर मातेचा प्रभाव लक्षणीय.',pa:'ਮਾਤ੍ਰੇਸ਼ ਦਸਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਕਰੀਅਰ ਅਤੇ ਘਰ ਵਿਚਕਾਰ ਮਜ਼ਬੂਤ ਸੰਬੰਧ ਪੈਦਾ ਕਰਦਾ ਹੈ। ਜਾਤਕ ਅਚੱਲ ਜਾਇਦਾਦ, ਪਰਿਵਾਰਕ ਵਪਾਰ ਜਾਂ ਘਰੋਂ ਕੰਮ ਕਰਦਾ ਹੈ। ਪੇਸ਼ੇ ਤੇ ਮਾਂ ਦਾ ਪ੍ਰਭਾਵ ਮਹੱਤਵਪੂਰਨ।',gu:'માતૃશ દશમા ભાવમાં હોય તો કારકિર્દી અને ઘર વચ્ચે મજબૂત જોડાણ સર્જે છે. જાતક સ્થાવર મિલકત, કૌટુંબિક વ્યવસાય કે ઘરેથી કામ કરે છે. વ્યવસાય પર માતાનો પ્રભાવ નોંધપાત્ર.'},
    11:{ta:'மாத்ரேஷ் பதினொன்றாம் பாவத்தில் இருந்தால் நிலம், தாயின் வலைப்பின்னல் மற்றும் அசையாச் சொத்து மூலம் லாபங்கள் வருகின்றன. ஜாதகர் வீட்டு மகிழ்ச்சி மற்றும் வசதியான வாழ்க்கை தொடர்பான ஆசைகளை நிறைவேற்றுகிறார்.',te:'మాత్రేశుడు పదకొండవ భావంలో ఉంటే భూమి, తల్లి నెట్‌వర్క్ మరియు స్థిరాస్తి ద్వారా లాభాలు వస్తాయి. జాతకుడు గృహ సౌఖ్యం మరియు సౌకర్యవంతమైన జీవితం సంబంధ ఆకాంక్షలను నెరవేరుస్తాడు.',bn:'মাত্রেশ একাদশ ভাবে থাকলে জমি, মাতার নেটওয়ার্ক ও স্থাবর সম্পত্তির মাধ্যমে লাভ আসে। জাতক গৃহসুখ ও আরামদায়ক জীবন সংক্রান্ত আকাঙ্ক্ষা পূরণ করে।',mr:'मातृश अकराव्या भावात असल्यास जमीन, मातेचे नेटवर्क व स्थावर मालमत्तेतून लाभ येतात. जातक गृहसुख व आरामदायी जीवन संबंधित आकांक्षा पूर्ण करतो.',pa:'ਮਾਤ੍ਰੇਸ਼ ਗਿਆਰਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਜ਼ਮੀਨ, ਮਾਂ ਦੇ ਨੈੱਟਵਰਕ ਅਤੇ ਅਚੱਲ ਜਾਇਦਾਦ ਰਾਹੀਂ ਲਾਭ ਆਉਂਦੇ ਹਨ। ਜਾਤਕ ਘਰੇਲੂ ਖੁਸ਼ੀ ਅਤੇ ਆਰਾਮਦਾਇਕ ਜੀਵਨ ਸੰਬੰਧੀ ਇੱਛਾਵਾਂ ਪੂਰੀਆਂ ਕਰਦਾ ਹੈ।',gu:'માતૃશ અગિયારમા ભાવમાં હોય તો જમીન, માતાનું નેટવર્ક અને સ્થાવર મિલકત દ્વારા લાભ આવે છે. જાતક ગૃહસુખ અને આરામદાયક જીવન સંબંધિત આકાંક્ષા પૂર્ણ કરે છે.'},
    12:{ta:'மாத்ரேஷ் பன்னிரண்டாம் பாவத்தில் இருந்தால் சொத்து இழப்பு, தாயிடமிருந்து பிரிவு அல்லது நிலத்துடன் வெளிநாட்டு குடியேற்றத்தைக் குறிக்கிறது. ஜாதகர் தனிமை, தியானம் அல்லது வெளிநாட்டு வாழ்வின் மூலம் உணர்வு அமைதியைக் காண்கிறார்.',te:'మాత్రేశుడు పన్నెండవ భావంలో ఉంటే ఆస్తి నష్టం, తల్లి నుండి ఎడబాటు లేదా భూమితో విదేశీ స్థిరనివాసాన్ని సూచిస్తుంది. జాతకుడు ఏకాంతం, ధ్యానం లేదా విదేశీ నివాసం ద్వారా భావోద్వేగ శాంతిని పొందుతాడు.',bn:'মাত্রেশ দ্বাদশ ভাবে থাকলে সম্পত্তি ক্ষতি, মাতা থেকে বিচ্ছেদ বা জমিসহ বিদেশে বসতি নির্দেশ করে। জাতক নির্জনতা, ধ্যান বা বিদেশে বসবাসের মাধ্যমে আবেগীয় শান্তি পায়।',mr:'मातृश बाराव्या भावात असल्यास मालमत्ता हानी, मातेपासून विभक्तता किंवा जमिनीसह परदेश वास दर्शवते. जातक एकांत, ध्यान किंवा परदेश वासातून भावनिक शांती पाहतो.',pa:'ਮਾਤ੍ਰੇਸ਼ ਬਾਰ੍ਹਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਜਾਇਦਾਦ ਹਾਨੀ, ਮਾਂ ਤੋਂ ਵਿਛੋੜਾ ਜਾਂ ਜ਼ਮੀਨ ਨਾਲ ਵਿਦੇਸ਼ੀ ਵਸੇਬਾ ਦਰਸਾਉਂਦਾ ਹੈ। ਜਾਤਕ ਇਕਾਂਤ, ਧਿਆਨ ਜਾਂ ਵਿਦੇਸ਼ੀ ਵਸੇਬੇ ਰਾਹੀਂ ਭਾਵਨਾਤਮਕ ਸ਼ਾਂਤੀ ਲੱਭਦਾ ਹੈ।',gu:'માતૃశ બારમા ભાવમાં હોય તો મિલકત હાનિ, માતાથી વિયોગ કે જમીન સાથે વિદેશ વસવાટ સૂચવે છે. જાતક એકાંત, ધ્યાન કે વિદેશ વસવાટ દ્વારા ભાવનાત્મક શાંતિ મેળવે છે.'},
  },
  5: {
    1:{ta:'புத்ரேஷ் முதலாம் பாவத்தில் இருந்தால் ஜாதகர் மிகவும் புத்திசாலி, படைப்பாற்றல் மிக்க மற்றும் தன் உற்சாகத்தில் குழந்தைத்தனமானவராகிறார். அவர்கள் இயற்கை ஆசிரியர்கள், தங்கள் புத்திக்காக போற்றப்படுகிறார்கள்.',te:'పుత్రేశుడు మొదటి భావంలో ఉంటే జాతకుడు అత్యంత తెలివైనవాడు, సృజనాత్మకుడు మరియు తన ఉత్సాహంలో పిల్లల వంటి వాడు అవుతాడు. వారు సహజ ఉపాధ్యాయులు, తమ బుద్ధికి ప్రశంసించబడతారు.',bn:'পুত্রেশ প্রথম ভাবে থাকলে জাতক অত্যন্ত বুদ্ধিমান, সৃজনশীল ও উৎসাহে শিশুসুলভ হয়। তারা স্বাভাবিক শিক্ষক এবং তাদের বুদ্ধির জন্য প্রশংসিত হয়।',mr:'पुत्रेश पहिल्या भावात असल्यास जातक अत्यंत बुद्धिमान, सर्जनशील व उत्साहात बालसुलभ होतो. ते नैसर्गिक शिक्षक असतात व त्यांच्या बुद्धीसाठी कौतुकास्पद ठरतात.',pa:'ਪੁਤ੍ਰੇਸ਼ ਪਹਿਲੇ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਜਾਤਕ ਬਹੁਤ ਬੁੱਧੀਮਾਨ, ਰਚਨਾਤਮਕ ਅਤੇ ਆਪਣੇ ਉਤਸ਼ਾਹ ਵਿੱਚ ਬਾਲ-ਸੁਲਭ ਹੁੰਦਾ ਹੈ। ਉਹ ਕੁਦਰਤੀ ਅਧਿਆਪਕ ਹੁੰਦੇ ਹਨ ਅਤੇ ਆਪਣੀ ਬੁੱਧੀ ਲਈ ਸਲਾਹੇ ਜਾਂਦੇ ਹਨ।',gu:'પુત્રેશ પ્રથમ ભાવમાં હોય તો જાતક અત્યંત બુદ્ધિમાન, સર્જનાત્મક અને પોતાના ઉત્સાહમાં બાળસુલભ હોય છે. તેઓ કુદરતી શિક્ષક હોય છે અને પોતાની બુદ્ધિ માટે વખણાય છે.'},
    2:{ta:'புத்ரேஷ் இரண்டாம் பாவத்தில் இருந்தால் புத்தி, குழந்தைகளின் பங்களிப்பு மற்றும் படைப்பு முயற்சிகள் மூலம் செல்வம் வருகிறது. ஜாதகருக்கு படித்த, படைப்பாற்றல் மிக்க குடும்பப் பின்னணி உண்டு.',te:'పుత్రేశుడు రెండవ భావంలో ఉంటే బుద్ధి, పిల్లల సహకారం మరియు సృజనాత్మక ప్రయత్నాల ద్వారా సంపద వస్తుంది. జాతకుడికి విద్యావంతమైన, సృజనాత్మక కుటుంబ నేపథ్యం ఉంటుంది.',bn:'পুত্রেশ দ্বিতীয় ভাবে থাকলে বুদ্ধি, সন্তানের অবদান ও সৃজনশীল প্রচেষ্টার মাধ্যমে সম্পদ আসে। জাতকের শিক্ষিত, সৃজনশীল পারিবারিক পটভূমি থাকে।',mr:'पुत्रेश दुसऱ्या भावात असल्यास बुद्धी, संततीचे योगदान व सर्जनशील प्रयत्नांतून संपत्ती येते. जातकाची शिक्षित, सर्जनशील कौटुंबिक पार्श्वभूमी असते.',pa:'ਪੁਤ੍ਰੇਸ਼ ਦੂਜੇ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਬੁੱਧੀ, ਬੱਚਿਆਂ ਦੇ ਯੋਗਦਾਨ ਅਤੇ ਰਚਨਾਤਮਕ ਯਤਨਾਂ ਰਾਹੀਂ ਦੌਲਤ ਆਉਂਦੀ ਹੈ। ਜਾਤਕ ਦਾ ਪੜ੍ਹਿਆ-ਲਿਖਿਆ, ਰਚਨਾਤਮਕ ਪਰਿਵਾਰਕ ਪਿਛੋਕੜ ਹੁੰਦਾ ਹੈ।',gu:'પુત્રેશ બીજા ભાવમાં હોય તો બુદ્ધિ, સંતાનના યોગદાન અને સર્જનાત્મક પ્રયત્નો દ્વારા સંપત્તિ આવે છે. જાતકની શિક્ષિત, સર્જનાત્મક કૌટુંબિક પૃષ્ઠભૂમિ હોય છે.'},
    3:{ta:'புத்ரேஷ் மூன்றாம் பாவத்தில் இருந்தால் படைப்பாற்றல் தொடர்பு மற்றும் தைரியத்துடன் இணைகிறது. ஜாதகர் எழுத்தாளர், கலைஞர் அல்லது நடிகராக இருக்கலாம், படைப்பு முயற்சிகளில் உடன்பிறந்தோர் ஆதரவால் பெரிதும் பயனடைகிறார்.',te:'పుత్రేశుడు మూడవ భావంలో ఉంటే సృజనాత్మకత సంభాషణ మరియు ధైర్యంతో కలుస్తుంది. జాతకుడు రచయిత, కళాకారుడు లేదా నటుడు కావచ్చు, సృజనాత్మక ప్రయత్నాలలో సహోదర మద్దతుతో ఎంతో ప్రయోజనం పొందుతాడు.',bn:'পুত্রেশ তৃতীয় ভাবে থাকলে সৃজনশীলতা যোগাযোগ ও সাহসের সাথে মিলিত হয়। জাতক লেখক, শিল্পী বা অভিনেতা হতে পারে এবং সৃজনশীল প্রচেষ্টায় ভাইবোনের সমর্থনে অনেক উপকৃত হয়।',mr:'पुत्रेश तिसऱ्या भावात असल्यास सर्जनशीलता संवाद व धैर्याशी जोडते. जातक लेखक, कलाकार किंवा अभिनेता असू शकतो व सर्जनशील प्रयत्नांत भावंडांच्या पाठिंब्याने खूप लाभ होतो.',pa:'ਪੁਤ੍ਰੇਸ਼ ਤੀਜੇ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਰਚਨਾਤਮਕਤਾ ਸੰਚਾਰ ਅਤੇ ਹੌਸਲੇ ਨਾਲ ਜੁੜਦੀ ਹੈ। ਜਾਤਕ ਲੇਖਕ, ਕਲਾਕਾਰ ਜਾਂ ਅਦਾਕਾਰ ਹੋ ਸਕਦਾ ਅਤੇ ਰਚਨਾਤਮਕ ਯਤਨਾਂ ਵਿੱਚ ਭੈਣ-ਭਰਾਵਾਂ ਦੇ ਸਹਾਰੇ ਨਾਲ ਬਹੁਤ ਲਾਭ ਹੁੰਦਾ ਹੈ।',gu:'પુત્રેશ ત્રીજા ભાવમાં હોય તો સર્જનાત્મકતા સંવાદ અને હિંમત સાથે જોડાય છે. જાતક લેખક, કલાકાર કે અભિનેતા હોઈ શકે અને સર્જનાત્મક પ્રયત્નોમાં ભાઈ-બહેનના ટેકાથી ખૂબ લાભ મેળવે છે.'},
    4:{ta:'புத்ரேஷ் நான்காம் பாவத்தில் இருந்தால் குழந்தைகள் மற்றும் வீட்டு அடிப்படையிலான படைப்பு நடவடிக்கைகள் மூலம் மகிழ்ச்சி வருகிறது. ஜாதகர் வீட்டில் கற்பிக்கலாம், கல்வி உள்கட்டமைப்பில் முதலீடு செய்யலாம் அல்லது ஆழமான அறிவுசார் வீட்டுச் சூழல் இருக்கலாம்.',te:'పుత్రేశుడు నాల్గవ భావంలో ఉంటే పిల్లలు మరియు గృహ-ఆధారిత సృజనాత్మక కార్యకలాపాల ద్వారా సంతోషం వస్తుంది. జాతకుడు ఇంట్లో బోధించవచ్చు, విద్యా మౌలిక సదుపాయాలలో పెట్టుబడి పెట్టవచ్చు లేదా లోతైన మేధో గృహ వాతావరణం కలిగి ఉండవచ్చు.',bn:'পুত্রেশ চতুর্থ ভাবে থাকলে সন্তান ও গৃহভিত্তিক সৃজনশীল কার্যক্রমের মাধ্যমে সুখ আসে। জাতক বাড়িতে শেখাতে পারে, শিক্ষা অবকাঠামোয় বিনিয়োগ করতে পারে বা গভীর বুদ্ধিবৃত্তিক গৃহ পরিবেশ থাকতে পারে।',mr:'पुत्रेश चौथ्या भावात असल्यास संतती व घर-आधारित सर्जनशील कृतींतून सुख मिळते. जातक घरी शिकवू शकतो, शैक्षणिक पायाभूत सुविधांत गुंतवणूक करू शकतो किंवा खोल बौद्धिक गृह वातावरण असू शकते.',pa:'ਪੁਤ੍ਰੇਸ਼ ਚੌਥੇ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਸੰਤਾਨ ਅਤੇ ਘਰ-ਆਧਾਰਿਤ ਰਚਨਾਤਮਕ ਗਤੀਵਿਧੀਆਂ ਰਾਹੀਂ ਖੁਸ਼ੀ ਆਉਂਦੀ ਹੈ। ਜਾਤਕ ਘਰ ਪੜ੍ਹਾ ਸਕਦਾ, ਵਿੱਦਿਅਕ ਢਾਂਚੇ ਵਿੱਚ ਨਿਵੇਸ਼ ਕਰ ਸਕਦਾ ਜਾਂ ਡੂੰਘਾ ਬੌਧਿਕ ਘਰੇਲੂ ਮਾਹੌਲ ਹੋ ਸਕਦਾ ਹੈ।',gu:'પુત્રેશ ચોથા ભાવમાં હોય તો સંતાન અને ઘર-આધારિત સર્જનાત્મક પ્રવૃત્તિઓ દ્વારા સુખ આવે છે. જાતક ઘરે ભણાવી શકે, શૈક્ષણિક માળખામાં રોકાણ કરી શકે કે ઊંડું બૌદ્ધિક ગૃહ વાતાવરણ હોઈ શકે.'},
    5:{ta:'புத்ரேஷ் தன் சொந்த பாவத்தில் இருப்பது புத்தி, காதல், குழந்தைகள் மற்றும் ஆன்மிக சாதனையை பெரிதும் வலுப்படுத்துகிறது. ஜாதகர் திறமையான குழந்தைகள், கூர்மையான புத்தி மற்றும் அதிர்ஷ்டத்தால் ஆசீர்வதிக்கப்படுகிறார்.',te:'పుత్రేశుడు తన స్వంత భావంలో ఉండటం బుద్ధి, ప్రేమ, పిల్లలు మరియు ఆధ్యాత్మిక సాధనను ఎంతో బలపరుస్తుంది. జాతకుడు ప్రతిభావంతులైన పిల్లలు, పదునైన బుద్ధి మరియు అదృష్టంతో ఆశీర్వదించబడతాడు.',bn:'পুত্রেশ নিজ ভাবে থাকা বুদ্ধি, প্রেম, সন্তান ও আধ্যাত্মিক সাধনাকে ব্যাপকভাবে শক্তিশালী করে। জাতক মেধাবী সন্তান, তীক্ষ্ণ বুদ্ধি ও সৌভাগ্যে আশীর্বাদিত হয়।',mr:'पुत्रेश स्वतःच्या भावात असणे बुद्धी, प्रेम, संतती व आध्यात्मिक साधना खूप बळकट करते. जातक प्रतिभावान संतती, तीक्ष्ण बुद्धी व सौभाग्याने आशीर्वादित होतो.',pa:'ਪੁਤ੍ਰੇਸ਼ ਆਪਣੇ ਭਾਵ ਵਿੱਚ ਹੋਣਾ ਬੁੱਧੀ, ਪਿਆਰ, ਸੰਤਾਨ ਅਤੇ ਅਧਿਆਤਮਕ ਸਾਧਨਾ ਨੂੰ ਬਹੁਤ ਮਜ਼ਬੂਤ ਕਰਦਾ ਹੈ। ਜਾਤਕ ਪ੍ਰਤਿਭਾਸ਼ਾਲੀ ਬੱਚਿਆਂ, ਤਿੱਖੀ ਬੁੱਧੀ ਅਤੇ ਕਿਸਮਤ ਨਾਲ ਬਖ਼ਸ਼ਿਆ ਜਾਂਦਾ ਹੈ।',gu:'પુત્રેશ પોતાના ભાવમાં હોવું બુદ્ધિ, પ્રેમ, સંતાન અને આધ્યાત્મિક સાધનાને ખૂબ મજબૂત કરે છે. જાતક પ્રતિભાશાળી સંતાન, તીક્ષ્ણ બુદ્ધિ અને સૌભાગ્યથી આશીર્વાદિત થાય છે.'},
    6:{ta:'புத்ரேஷ் ஆறாம் பாவத்தில் இருந்தால் காதல், குழந்தைகள் மற்றும் கல்வியில் சவால்களை உருவாக்குகிறது. ஜாதகர் குழந்தை பேற்றில் தடைகளை எதிர்கொள்ளலாம் அல்லது கல்வி முயற்சிகளில் போராடலாம், ஆனால் போட்டித் தேர்வுகளில் வெற்றி பெறலாம்.',te:'పుత్రేశుడు ఆరవ భావంలో ఉంటే ప్రేమ, పిల్లలు మరియు విద్యలో సవాళ్లను సృష్టిస్తుంది. జాతకుడు సంతాన ప్రాప్తిలో అడ్డంకులను ఎదుర్కోవచ్చు లేదా విద్యా ప్రయత్నాలలో కష్టపడవచ్చు, కానీ పోటీ పరీక్షలలో విజయం సాధించవచ్చు.',bn:'পুত্রেশ ষষ্ঠ ভাবে থাকলে প্রেম, সন্তান ও শিক্ষায় চ্যালেঞ্জ সৃষ্টি করে। জাতক সন্তান লাভে বাধার সম্মুখীন হতে পারে বা শিক্ষায় সংগ্রাম করতে পারে, তবে প্রতিযোগিতামূলক পরীক্ষায় সফল হতে পারে।',mr:'पुत्रेश सहाव्या भावात असल्यास प्रेम, संतती व शिक्षणात आव्हाने निर्माण करते. जातकाला संतती प्राप्तीत अडथळे येऊ शकतात किंवा शैक्षणिक प्रयत्नांत संघर्ष होऊ शकतो, पण स्पर्धात्मक परीक्षांत यश मिळू शकते.',pa:'ਪੁਤ੍ਰੇਸ਼ ਛੇਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਪਿਆਰ, ਸੰਤਾਨ ਅਤੇ ਸਿੱਖਿਆ ਵਿੱਚ ਚੁਣੌਤੀਆਂ ਪੈਦਾ ਕਰਦਾ ਹੈ। ਜਾਤਕ ਸੰਤਾਨ ਪ੍ਰਾਪਤੀ ਵਿੱਚ ਰੁਕਾਵਟਾਂ ਦਾ ਸਾਹਮਣਾ ਕਰ ਸਕਦਾ ਜਾਂ ਸਿੱਖਿਆ ਵਿੱਚ ਸੰਘਰਸ਼ ਕਰ ਸਕਦਾ, ਪਰ ਮੁਕਾਬਲੇ ਦੀਆਂ ਪ੍ਰੀਖਿਆਵਾਂ ਵਿੱਚ ਸਫਲ ਹੋ ਸਕਦਾ ਹੈ।',gu:'પુત્રેશ છઠ્ઠા ભાવમાં હોય તો પ્રેમ, સંતાન અને શિક્ષણમાં પડકારો સર્જે છે. જાતક સંતાન પ્રાપ્તિમાં અવરોધોનો સામનો કરી શકે કે શિક્ષણમાં સંઘર્ષ કરી શકે, પણ સ્પર્ધાત્મક પરીક્ષાઓમાં સફળ થઈ શકે.'},
    7:{ta:'புத்ரேஷ் ஏழாம் பாவத்தில் இருந்தால் திருமணத்தில் காதல் கலக்கிறது. ஜாதகர் காதல் திருமணம் செய்கிறார், அறிவுசார் ரீதியில் பொருந்தும் துணை உண்டு. வாழ்க்கைத்துணையுடன் வணிக மற்றும் சூதாட்ட முதலீடுகள் பொதுவானவை.',te:'పుత్రేశుడు ఏడవ భావంలో ఉంటే వివాహంలో ప్రేమ కలుస్తుంది. జాతకుడు ప్రేమ వివాహం చేసుకుంటాడు, మేధోపరంగా అనుకూలమైన భాగస్వామి ఉంటాడు. జీవిత భాగస్వామితో వ్యాపార మరియు ఊహాజల్పన పెట్టుబడులు సాధారణం.',bn:'পুত্রেশ সপ্তম ভাবে থাকলে বিবাহে প্রেম মিশে যায়। জাতক প্রেম বিবাহ করে, বুদ্ধিবৃত্তিকভাবে সামঞ্জস্যপূর্ণ সঙ্গী থাকে। জীবনসঙ্গীর সাথে ব্যবসা ও ফাটকা বিনিয়োগ সাধারণ।',mr:'पुत्रेश सातव्या भावात असल्यास विवाहात प्रेम मिसळते. जातक प्रेमविवाह करतो, बौद्धिकदृष्ट्या सुसंगत जोडीदार असतो. जोडीदारासह व्यापार व सट्टा गुंतवणूक सामान्य.',pa:'ਪੁਤ੍ਰੇਸ਼ ਸੱਤਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਵਿਆਹ ਵਿੱਚ ਪਿਆਰ ਰਲਦਾ ਹੈ। ਜਾਤਕ ਪ੍ਰੇਮ ਵਿਆਹ ਕਰਦਾ, ਬੌਧਿਕ ਤੌਰ ਤੇ ਅਨੁਕੂਲ ਸਾਥੀ ਹੁੰਦਾ ਹੈ। ਜੀਵਨ ਸਾਥੀ ਨਾਲ ਵਪਾਰ ਅਤੇ ਸੱਟੇ ਦੇ ਨਿਵੇਸ਼ ਆਮ।',gu:'પુત્રેશ સાતમા ભાવમાં હોય તો લગ્નમાં પ્રેમ ભળે છે. જાતક પ્રેમ લગ્ન કરે, બૌદ્ધિક રીતે અનુકૂળ સાથી હોય. જીવનસાથી સાથે વ્યાપાર અને સટ્ટા રોકાણ સામાન્ય.'},
    8:{ta:'புத்ரேஷ் எட்டாம் பாவத்தில் இருந்தால் மறைஞானம், மறைபொருள் விஷயங்கள் மற்றும் ஆழமான ஆராய்ச்சியில் ஆர்வத்தை உருவாக்குகிறது. ஜாதகர் குழந்தைகள் தொடர்பான சவால்களை எதிர்கொள்ளலாம் ஆனால் ஆழமான ஆன்மிக ஞானமும் உள்ளுணர்வும் உண்டு.',te:'పుత్రేశుడు ఎనిమిదవ భావంలో ఉంటే గూఢ శాస్త్రాలు, రహస్య విషయాలు మరియు లోతైన పరిశోధనలో ఆసక్తిని సృష్టిస్తుంది. జాతకుడు పిల్లల సంబంధ సవాళ్లను ఎదుర్కోవచ్చు కానీ లోతైన ఆధ్యాత్మిక జ్ఞానం మరియు అంతర్ దృష్టి కలిగి ఉంటాడు.',bn:'পুত্রেশ অষ্টম ভাবে থাকলে গূঢ় বিদ্যা, রহস্যময় বিষয় ও গভীর গবেষণায় আগ্রহ সৃষ্টি করে। জাতক সন্তান সংক্রান্ত চ্যালেঞ্জের সম্মুখীন হতে পারে কিন্তু গভীর আধ্যাত্মিক প্রজ্ঞা ও স্বজ্ঞা থাকে।',mr:'पुत्रेश आठव्या भावात असल्यास गूढ विद्या, रहस्यमय विषय व खोल संशोधनात रुची निर्माण करते. जातकाला संतती संबंधित आव्हाने येऊ शकतात पण खोल आध्यात्मिक ज्ञान व अंतर्ज्ञान असते.',pa:'ਪੁਤ੍ਰੇਸ਼ ਅੱਠਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਗੂੜ੍ਹ ਵਿਦਿਆ, ਰਹੱਸਮਈ ਵਿਸ਼ਿਆਂ ਅਤੇ ਡੂੰਘੀ ਖੋਜ ਵਿੱਚ ਰੁਚੀ ਪੈਦਾ ਕਰਦਾ ਹੈ। ਜਾਤਕ ਸੰਤਾਨ ਸੰਬੰਧੀ ਚੁਣੌਤੀਆਂ ਦਾ ਸਾਹਮਣਾ ਕਰ ਸਕਦਾ ਪਰ ਡੂੰਘਾ ਅਧਿਆਤਮਕ ਗਿਆਨ ਅਤੇ ਸੂਝ ਹੁੰਦੀ ਹੈ।',gu:'પુત્રેશ આઠમા ભાવમાં હોય તો ગૂઢ વિદ્યા, રહસ્યમય વિષયો અને ઊંડા સંશોધનમાં રસ સર્જે છે. જાતક સંતાન સંબંધિત પડકારોનો સામનો કરી શકે પણ ઊંડું આધ્યાત્મિક જ્ઞાન અને અંતઃપ્રેરણા હોય છે.'},
    9:{ta:'புத்ரேஷ் ஒன்பதாம் பாவத்தில் இருந்தால் (இரண்டு திரிகோணங்கள் சந்திப்பது) தர்ம-கர்மாதிபதி யோகத்தை உருவாக்கும் மிக சுபமான சேர்க்கைகளில் ஒன்று. ஜாதகர் கற்றறிந்த, நல்லொழுக்கமுள்ள, ஆன்மிக ரீதியில் வளர்ந்த மற்றும் சிறந்த குழந்தைகளால் ஆசீர்வதிக்கப்பட்டவராகிறார்.',te:'పుత్రేశుడు తొమ్మిదవ భావంలో ఉంటే (రెండు త్రికోణాలు కలవడం) ధర్మ-కర్మాధిపతి యోగాన్ని ఏర్పరచే అత్యంత శుభ కలయికలలో ఒకటి. జాతకుడు విద్వాంసుడు, సద్గుణవంతుడు, ఆధ్యాత్మికంగా ఎదిగినవాడు మరియు ఉత్తమ పిల్లలతో ఆశీర్వదించబడతాడు.',bn:'পুত্রেশ নবম ভাবে থাকলে (দুই ত্রিকোণের মিলন) ধর্ম-কর্মাধিপতি যোগ সৃষ্টিকারী অত্যন্ত শুভ সংমিশ্রণগুলির একটি। জাতক বিদ্বান, সদ্গুণী, আধ্যাত্মিকভাবে উন্নত ও উত্তম সন্তানে আশীর্বাদিত হয়।',mr:'पुत्रेश नवव्या भावात असल्यास (दोन त्रिकोणांचे मिलन) धर्म-कर्माधिपती योग बनवणाऱ्या अत्यंत शुभ संयोगांपैकी एक. जातक विद्वान, सद्गुणी, आध्यात्मिकदृष्ट्या उन्नत व उत्तम संततीने आशीर्वादित होतो.',pa:'ਪੁਤ੍ਰੇਸ਼ ਨੌਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ (ਦੋ ਤ੍ਰਿਕੋਣਾਂ ਦਾ ਮਿਲਣ) ਧਰਮ-ਕਰਮਾਧਿਪਤੀ ਯੋਗ ਬਣਾਉਣ ਵਾਲੇ ਬਹੁਤ ਸ਼ੁਭ ਸੰਯੋਗਾਂ ਵਿੱਚੋਂ ਇੱਕ। ਜਾਤਕ ਵਿਦਵਾਨ, ਸਦਗੁਣੀ, ਅਧਿਆਤਮਕ ਤੌਰ ਤੇ ਉੱਨਤ ਅਤੇ ਉੱਤਮ ਸੰਤਾਨ ਨਾਲ ਬਖ਼ਸ਼ਿਆ ਹੁੰਦਾ ਹੈ।',gu:'પુત્રેશ નવમા ભાવમાં હોય તો (બે ત્રિકોણનું મિલન) ધર્મ-કર્માધિપતિ યોગ બનાવતા અત્યંત શુભ સંયોજનોમાંનું એક. જાતક વિદ્વાન, સદ્ગુણી, આધ્યાત્મિક રીતે ઉન્નત અને ઉત્તમ સંતાનથી આશીર્વાદિત થાય છે.'},
    10:{ta:'புத்ரேஷ் பத்தாம் பாவத்தில் இருந்தால் கல்வி, பொழுதுபோக்கு, கலைகள் அல்லது சூதாட்டத்தில் தொழில் உருவாகிறது. ஜாதகர் அறிவுசார் அல்லது படைப்பு முயற்சிகளால் புகழ் பெறுகிறார், நன்கு அறியப்பட்ட ஆசிரியர் அல்லது கலைஞராகலாம்.',te:'పుత్రేశుడు పదవ భావంలో ఉంటే విద్య, వినోదం, కళలు లేదా ఊహాజల్పనలో వృత్తి ఏర్పడుతుంది. జాతకుడు మేధో లేదా సృజనాత్మక ప్రయత్నాల ద్వారా కీర్తి పొంది, ప్రసిద్ధ ఉపాధ్యాయుడు లేదా కళాకారుడు కావచ్చు.',bn:'পুত্রেশ দশম ভাবে থাকলে শিক্ষা, বিনোদন, কলা বা ফাটকায় কর্মজীবন গড়ে। জাতক বুদ্ধিবৃত্তিক বা সৃজনশীল প্রচেষ্টার মাধ্যমে খ্যাতি পায় ও সুপরিচিত শিক্ষাবিদ বা শিল্পী হতে পারে।',mr:'पुत्रेश दहाव्या भावात असल्यास शिक्षण, मनोरंजन, कला किंवा सट्ट्यात करिअर घडते. जातक बौद्धिक किंवा सर्जनशील प्रयत्नांतून प्रसिद्धी मिळवतो व नामांकित शिक्षक किंवा कलाकार होऊ शकतो.',pa:'ਪੁਤ੍ਰੇਸ਼ ਦਸਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਸਿੱਖਿਆ, ਮਨੋਰੰਜਨ, ਕਲਾ ਜਾਂ ਸੱਟੇ ਵਿੱਚ ਕਰੀਅਰ ਬਣਦਾ ਹੈ। ਜਾਤਕ ਬੌਧਿਕ ਜਾਂ ਰਚਨਾਤਮਕ ਯਤਨਾਂ ਰਾਹੀਂ ਸ਼ੋਹਰਤ ਪਾਉਂਦਾ ਅਤੇ ਮਸ਼ਹੂਰ ਸਿੱਖਿਅਕ ਜਾਂ ਕਲਾਕਾਰ ਬਣ ਸਕਦਾ ਹੈ।',gu:'પુત્રેશ દશમા ભાવમાં હોય તો શિક્ષણ, મનોરંજન, કલા કે સટ્ટામાં કારકિર્દી બને છે. જાતક બૌદ્ધિક કે સર્જનાત્મક પ્રયત્નો દ્વારા કીર્તિ મેળવે અને જાણીતો શિક્ષક કે કલાકાર બની શકે.'},
    11:{ta:'புத்ரேஷ் பதினொன்றாம் பாவத்தில் இருந்தால் சூதாட்டம், குழந்தைகளின் வெற்றி மற்றும் படைப்பு முயற்சிகள் மூலம் லாபங்கள் வருகின்றன. ஜாதகர் நிதி விஷயங்களில் மிகவும் புத்திசாலி, அறிவின் மூலம் ஆசைகளை அடைகிறார்.',te:'పుత్రేశుడు పదకొండవ భావంలో ఉంటే ఊహాజల్పన, పిల్లల విజయం మరియు సృజనాత్మక వెంచర్ల ద్వారా లాభాలు వస్తాయి. జాతకుడు ఆర్థిక విషయాలలో అత్యంత తెలివైనవాడు, జ్ఞానం ద్వారా ఆకాంక్షలను సాధిస్తాడు.',bn:'পুত্রেশ একাদশ ভাবে থাকলে ফাটকা, সন্তানের সাফল্য ও সৃজনশীল উদ্যোগের মাধ্যমে লাভ আসে। জাতক আর্থিক বিষয়ে অত্যন্ত বুদ্ধিমান, জ্ঞানের মাধ্যমে আকাঙ্ক্ষা অর্জন করে।',mr:'पुत्रेश अकराव्या भावात असल्यास सट्टा, संततीचे यश व सर्जनशील उपक्रमांतून लाभ येतात. जातक आर्थिक बाबतीत अत्यंत बुद्धिमान असून ज्ञानाद्वारे आकांक्षा गाठतो.',pa:'ਪੁਤ੍ਰੇਸ਼ ਗਿਆਰਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਸੱਟੇ, ਸੰਤਾਨ ਦੀ ਸਫਲਤਾ ਅਤੇ ਰਚਨਾਤਮਕ ਉੱਦਮਾਂ ਰਾਹੀਂ ਲਾਭ ਆਉਂਦੇ ਹਨ। ਜਾਤਕ ਵਿੱਤੀ ਮਾਮਲਿਆਂ ਵਿੱਚ ਬਹੁਤ ਬੁੱਧੀਮਾਨ ਹੋ ਕੇ ਗਿਆਨ ਰਾਹੀਂ ਇੱਛਾਵਾਂ ਪ੍ਰਾਪਤ ਕਰਦਾ ਹੈ।',gu:'પુત્રેશ અગિયારમા ભાવમાં હોય તો સટ્ટા, સંતાનની સફળતા અને સર્જનાત્મક સાહસો દ્વારા લાભ આવે છે. જાતક આર્થિક બાબતોમાં અત્યંત બુદ્ધિમાન હોઈ જ્ઞાન દ્વારા આકાંક્ષા મેળવે છે.'},
    12:{ta:'புத்ரேஷ் பன்னிரண்டாம் பாவத்தில் இருந்தால் குழந்தைகள் மீதான செலவு, குழந்தைகளிடமிருந்து பிரிவு அல்லது குழந்தைகள் வெளிநாட்டில் வாழ்வதைக் குறிக்கிறது. ஜாதகருக்கு ஆன்மிக குழந்தைகள் இருக்கலாம் அல்லது தியானம் மற்றும் மந்திர சாதனையில் ஆழ்ந்த ஆர்வம் இருக்கலாம்.',te:'పుత్రేశుడు పన్నెండవ భావంలో ఉంటే పిల్లలపై ఖర్చు, పిల్లల నుండి ఎడబాటు లేదా పిల్లలు విదేశాలలో నివసించడాన్ని సూచిస్తుంది. జాతకుడికి ఆధ్యాత్మిక పిల్లలు ఉండవచ్చు లేదా ధ్యానం మరియు మంత్ర సాధనలో లోతైన ఆసక్తి ఉండవచ్చు.',bn:'পুত্রেশ দ্বাদশ ভাবে থাকলে সন্তানের ওপর ব্যয়, সন্তান থেকে বিচ্ছেদ বা সন্তান বিদেশে বসবাস নির্দেশ করে। জাতকের আধ্যাত্মিক সন্তান থাকতে পারে বা ধ্যান ও মন্ত্র সাধনায় গভীর আগ্রহ থাকতে পারে।',mr:'पुत्रेश बाराव्या भावात असल्यास संततीवर खर्च, संततीपासून विभक्तता किंवा संतती परदेशात राहणे दर्शवते. जातकाला आध्यात्मिक संतती असू शकते किंवा ध्यान व मंत्र साधनेत खोल रुची असू शकते.',pa:'ਪੁਤ੍ਰੇਸ਼ ਬਾਰ੍ਹਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਸੰਤਾਨ ਤੇ ਖਰਚ, ਸੰਤਾਨ ਤੋਂ ਵਿਛੋੜਾ ਜਾਂ ਸੰਤਾਨ ਦਾ ਵਿਦੇਸ਼ ਵਾਸ ਦਰਸਾਉਂਦਾ ਹੈ। ਜਾਤਕ ਦੀ ਆਧਿਆਤਮਕ ਸੰਤਾਨ ਹੋ ਸਕਦੀ ਜਾਂ ਧਿਆਨ ਅਤੇ ਮੰਤਰ ਸਾਧਨਾ ਵਿੱਚ ਡੂੰਘੀ ਰੁਚੀ ਹੋ ਸਕਦੀ ਹੈ।',gu:'પુત્રેશ બારમા ભાવમાં હોય તો સંતાન પર ખર્ચ, સંતાનથી વિયોગ કે સંતાન વિદેશમાં વસવાટ સૂચવે છે. જાતકને આધ્યાત્મિક સંતાન હોઈ શકે કે ધ્યાન અને મંત્ર સાધનામાં ઊંડો રસ હોઈ શકે.'},
  },
  6: {
    1:{ta:'ரிபேஷ் முதலாம் பாவத்தில் இருந்தால் ஆரோக்கிய பிரச்சினைகள், எதிரிகளுடன் மோதல்கள் மற்றும் போராடும் ஆளுமையை ஏற்படுத்தலாம். இருப்பினும், ஜாதகர் எதிர்ப்பை வெல்லும் மற்றும் போட்டித் துறைகளில் செழிக்கும் சக்திவாய்ந்த போராளியாகிறார்.',te:'రిపేశుడు మొదటి భావంలో ఉంటే ఆరోగ్య సమస్యలు, శత్రువులతో ఘర్షణలు మరియు పోరాట స్వభావాన్ని కలిగించవచ్చు. అయితే, జాతకుడు వ్యతిరేకతను అధిగమించి పోటీ రంగాలలో వర్ధిల్లే శక్తివంతమైన యోధుడు అవుతాడు.',bn:'রিপেশ প্রথম ভাবে থাকলে স্বাস্থ্য সমস্যা, শত্রুর সাথে দ্বন্দ্ব ও যুদ্ধপ্রবণ ব্যক্তিত্ব হতে পারে। তবে জাতক বিরোধিতা অতিক্রমকারী ও প্রতিযোগিতামূলক ক্ষেত্রে সমৃদ্ধ শক্তিশালী যোদ্ধা হয়।',mr:'रिपेश पहिल्या भावात असल्यास आरोग्य समस्या, शत्रूंशी संघर्ष व लढाऊ स्वभाव होऊ शकतो. तथापि, जातक विरोध पार करणारा व स्पर्धात्मक क्षेत्रांत भरभराटीला येणारा शक्तिशाली योद्धा होतो.',pa:'ਰਿਪੇਸ਼ ਪਹਿਲੇ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਸਿਹਤ ਸਮੱਸਿਆਵਾਂ, ਦੁਸ਼ਮਣਾਂ ਨਾਲ ਟਕਰਾਅ ਅਤੇ ਲੜਾਕੂ ਸੁਭਾਅ ਹੋ ਸਕਦਾ ਹੈ। ਫਿਰ ਵੀ, ਜਾਤਕ ਵਿਰੋਧ ਪਾਰ ਕਰਨ ਵਾਲਾ ਅਤੇ ਮੁਕਾਬਲੇ ਵਾਲੇ ਖੇਤਰਾਂ ਵਿੱਚ ਵਧਣ-ਫੁੱਲਣ ਵਾਲਾ ਸ਼ਕਤੀਸ਼ਾਲੀ ਯੋਧਾ ਹੁੰਦਾ ਹੈ।',gu:'રિપેશ પ્રથમ ભાવમાં હોય તો આરોગ્ય સમસ્યાઓ, શત્રુઓ સાથે સંઘર્ષ અને લડાયક વ્યક્તિત્વ થઈ શકે. તેમ છતાં, જાતક વિરોધ પાર કરનાર અને સ્પર્ધાત્મક ક્ષેત્રોમાં સમૃદ્ધ થનાર શક્તિશાળી યોદ્ધો હોય છે.'},
    2:{ta:'ரிபேஷ் இரண்டாம் பாவத்தில் இருந்தால் ஆரோக்கியம் மற்றும் சட்ட விஷயங்களுக்கு செலவும் சாத்தியமான கடன்களும் ஏற்படுகின்றன. பணத்தை முன்னிட்டு குடும்ப மோதல் சாத்தியம். இருப்பினும், சுகாதாரம் அல்லது சட்டத் தொழில்களிலிருந்து வருமானமும் குறிக்கப்படுகிறது.',te:'రిపేశుడు రెండవ భావంలో ఉంటే ఆరోగ్యం మరియు న్యాయ విషయాలపై ఖర్చు మరియు సాధ్యమైన అప్పులు కలుగుతాయి. డబ్బు కోసం కుటుంబ ఘర్షణ సాధ్యం. అయితే, ఆరోగ్య సంరక్షణ లేదా న్యాయ వృత్తుల నుండి ఆదాయం కూడా సూచించబడుతుంది.',bn:'রিপেশ দ্বিতীয় ভাবে থাকলে স্বাস্থ্য ও আইনি বিষয়ে ব্যয় এবং সম্ভাব্য ঋণ হয়। অর্থ নিয়ে পারিবারিক দ্বন্দ্ব সম্ভব। তবে স্বাস্থ্যসেবা বা আইনি পেশা থেকে আয়ও নির্দেশিত।',mr:'रिपेश दुसऱ्या भावात असल्यास आरोग्य व कायदेशीर बाबींवर खर्च व संभाव्य कर्ज होते. पैशावरून कौटुंबिक संघर्ष शक्य. तथापि, आरोग्यसेवा किंवा कायदेशीर व्यवसायांतून उत्पन्नही सूचित होते.',pa:'ਰਿਪੇਸ਼ ਦੂਜੇ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਸਿਹਤ ਅਤੇ ਕਾਨੂੰਨੀ ਮਾਮਲਿਆਂ ਤੇ ਖਰਚ ਅਤੇ ਸੰਭਾਵੀ ਕਰਜ਼ ਹੁੰਦਾ ਹੈ। ਪੈਸੇ ਨੂੰ ਲੈ ਕੇ ਪਰਿਵਾਰਕ ਟਕਰਾਅ ਸੰਭਵ। ਫਿਰ ਵੀ, ਸਿਹਤ ਸੇਵਾ ਜਾਂ ਕਾਨੂੰਨੀ ਪੇਸ਼ਿਆਂ ਤੋਂ ਆਮਦਨ ਵੀ ਸੰਕੇਤਿਤ।',gu:'રિપેશ બીજા ભાવમાં હોય તો આરોગ્ય અને કાનૂની બાબતો પર ખર્ચ અને સંભવિત દેવું થાય છે. પૈસા બાબતે કૌટુંબિક સંઘર્ષ શક્ય. તેમ છતાં, આરોગ્યસેવા કે કાનૂની વ્યવસાયોથી આવક પણ સૂચવાય છે.'},
    3:{ta:'ரிபேஷ் மூன்றாம் பாவத்தில் இருந்தால் உடன்பிறந்தோருடன் மோதல்கள் மற்றும் போட்டித் தொடர்பை உருவாக்குகிறது. ஜாதகர் சட்ட, மருத்துவ அல்லது சமூக பிரச்சினைகள் பற்றி எழுதலாம். உடன்பிறந்தோர் பிரச்சினைகளை ஏற்படுத்தலாம்.',te:'రిపేశుడు మూడవ భావంలో ఉంటే సహోదరులతో ఘర్షణలు మరియు పోటీ సంభాషణను సృష్టిస్తుంది. జాతకుడు న్యాయ, వైద్య లేదా సామాజిక సమస్యల గురించి రాయవచ్చు. సహోదరులు సమస్యలను కలిగించవచ్చు.',bn:'রিপেশ তৃতীয় ভাবে থাকলে ভাইবোনের সাথে দ্বন্দ্ব ও প্রতিযোগিতামূলক যোগাযোগ সৃষ্টি করে। জাতক আইনি, চিকিৎসা বা সামাজিক বিষয়ে লিখতে পারে। ভাইবোন সমস্যা সৃষ্টি করতে পারে।',mr:'रिपेश तिसऱ्या भावात असल्यास भावंडांशी संघर्ष व स्पर्धात्मक संवाद निर्माण करते. जातक कायदेशीर, वैद्यकीय किंवा सामाजिक मुद्द्यांवर लिहू शकतो. भावंडे समस्या निर्माण करू शकतात.',pa:'ਰਿਪੇਸ਼ ਤੀਜੇ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਭੈਣ-ਭਰਾਵਾਂ ਨਾਲ ਟਕਰਾਅ ਅਤੇ ਮੁਕਾਬਲੇ ਵਾਲਾ ਸੰਚਾਰ ਪੈਦਾ ਕਰਦਾ ਹੈ। ਜਾਤਕ ਕਾਨੂੰਨੀ, ਡਾਕਟਰੀ ਜਾਂ ਸਮਾਜਿਕ ਮੁੱਦਿਆਂ ਤੇ ਲਿਖ ਸਕਦਾ ਹੈ। ਭੈਣ-ਭਰਾ ਸਮੱਸਿਆਵਾਂ ਪੈਦਾ ਕਰ ਸਕਦੇ ਹਨ।',gu:'રિપેશ ત્રીજા ભાવમાં હોય તો ભાઈ-બહેન સાથે સંઘર્ષ અને સ્પર્ધાત્મક સંવાદ સર્જે છે. જાતક કાનૂની, તબીબી કે સામાજિક મુદ્દાઓ પર લખી શકે. ભાઈ-બહેન સમસ્યાઓ સર્જી શકે.'},
    4:{ta:'ரிபேஷ் நான்காம் பாவத்தில் இருந்தால் வீட்டு மோதல்கள், தாயின் ஆரோக்கிய பிரச்சினைகள் அல்லது சொத்து தகராறுகளை ஏற்படுத்தலாம். ஜாதகர் வீட்டில் சுகாதாரப் பணி செய்யலாம் அல்லது குடும்பத்தில் போட்டி நிலைமைகளை எதிர்கொள்ளலாம்.',te:'రిపేశుడు నాల్గవ భావంలో ఉంటే గృహ ఘర్షణలు, తల్లి ఆరోగ్య సమస్యలు లేదా ఆస్తి వివాదాలను కలిగించవచ్చు. జాతకుడు ఇంట్లో ఆరోగ్య సంరక్షణ పని చేయవచ్చు లేదా కుటుంబంలో పోటీ పరిస్థితులను ఎదుర్కోవచ్చు.',bn:'রিপেশ চতুর্থ ভাবে থাকলে গৃহবিরোধ, মাতার স্বাস্থ্য সমস্যা বা সম্পত্তি বিরোধ হতে পারে। জাতক বাড়িতে স্বাস্থ্যসেবার কাজ করতে পারে বা পরিবারে প্রতিযোগিতামূলক পরিস্থিতির সম্মুখীন হতে পারে।',mr:'रिपेश चौथ्या भावात असल्यास घरगुती संघर्ष, मातेच्या आरोग्य समस्या किंवा मालमत्ता वाद होऊ शकतात. जातक घरी आरोग्यसेवेचे काम करू शकतो किंवा कुटुंबात स्पर्धात्मक परिस्थितीला सामोरा जाऊ शकतो.',pa:'ਰਿਪੇਸ਼ ਚੌਥੇ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਘਰੇਲੂ ਟਕਰਾਅ, ਮਾਂ ਦੀ ਸਿਹਤ ਸਮੱਸਿਆਵਾਂ ਜਾਂ ਜਾਇਦਾਦ ਝਗੜੇ ਹੋ ਸਕਦੇ ਹਨ। ਜਾਤਕ ਘਰ ਸਿਹਤ ਸੇਵਾ ਦਾ ਕੰਮ ਕਰ ਸਕਦਾ ਜਾਂ ਪਰਿਵਾਰ ਵਿੱਚ ਮੁਕਾਬਲੇ ਵਾਲੀਆਂ ਸਥਿਤੀਆਂ ਦਾ ਸਾਹਮਣਾ ਕਰ ਸਕਦਾ ਹੈ।',gu:'રિપેશ ચોથા ભાવમાં હોય તો ઘરેલું સંઘર્ષ, માતાની આરોગ્ય સમસ્યાઓ કે મિલકત વિવાદ થઈ શકે. જાતક ઘરે આરોગ્યસેવાનું કામ કરી શકે કે કુટુંબમાં સ્પર્ધાત્મક પરિસ્થિતિનો સામનો કરી શકે.'},
    5:{ta:'ரிபேஷ் ஐந்தாம் பாவத்தில் இருந்தால் குழந்தைகள், கல்வி மற்றும் காதலில் நோய் அல்லது மோதல் ஆற்றல் தாக்கம் செலுத்துகிறது. ஜாதகர் போட்டிக் கல்வி, விளையாட்டுப் பயிற்சியில் பணிபுரியலாம் அல்லது குழந்தைகளின் ஆரோக்கிய பிரச்சினைகளை கையாளலாம்.',te:'రిపేశుడు ఐదవ భావంలో ఉంటే పిల్లలు, విద్య మరియు ప్రేమపై వ్యాధి లేదా ఘర్షణ శక్తి ప్రభావం చూపుతుంది. జాతకుడు పోటీ విద్య, క్రీడా శిక్షణలో పని చేయవచ్చు లేదా పిల్లల ఆరోగ్య సమస్యలను నిర్వహించవచ్చు.',bn:'রিপেশ পঞ্চম ভাবে থাকলে সন্তান, শিক্ষা ও প্রেমে রোগ বা দ্বন্দ্ব শক্তির প্রভাব পড়ে। জাতক প্রতিযোগিতামূলক শিক্ষা, ক্রীড়া প্রশিক্ষণে কাজ করতে পারে বা সন্তানের স্বাস্থ্য সমস্যা সামলাতে পারে।',mr:'रिपेश पाचव्या भावात असल्यास संतती, शिक्षण व प्रेमावर रोग किंवा संघर्ष ऊर्जेचा प्रभाव पडतो. जातक स्पर्धात्मक शिक्षण, क्रीडा प्रशिक्षणात काम करू शकतो किंवा संततीच्या आरोग्य समस्या हाताळू शकतो.',pa:'ਰਿਪੇਸ਼ ਪੰਜਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਸੰਤਾਨ, ਸਿੱਖਿਆ ਅਤੇ ਪਿਆਰ ਤੇ ਰੋਗ ਜਾਂ ਟਕਰਾਅ ਊਰਜਾ ਦਾ ਪ੍ਰਭਾਵ ਪੈਂਦਾ ਹੈ। ਜਾਤਕ ਮੁਕਾਬਲੇ ਵਾਲੀ ਸਿੱਖਿਆ, ਖੇਡ ਸਿਖਲਾਈ ਵਿੱਚ ਕੰਮ ਕਰ ਸਕਦਾ ਜਾਂ ਸੰਤਾਨ ਦੀਆਂ ਸਿਹਤ ਸਮੱਸਿਆਵਾਂ ਸੰਭਾਲ ਸਕਦਾ ਹੈ।',gu:'રિપેશ પાંચમા ભાવમાં હોય તો સંતાન, શિક્ષણ અને પ્રેમ પર રોગ કે સંઘર્ષ ઊર્જાનો પ્રભાવ પડે છે. જાતક સ્પર્ધાત્મક શિક્ષણ, રમત તાલીમમાં કામ કરી શકે કે સંતાનની આરોગ્ય સમસ્યાઓ સંભાળી શકે.'},
    6:{ta:'ரிபேஷ் தன் சொந்த பாவத்தில் இருப்பது எதிரிகளை வெல்வதற்கும், சட்டப் போராட்டங்களில் வெற்றி பெறுவதற்கும், நோய்களை வெல்வதற்கும் சக்திவாய்ந்தது. ஜாதகர் நெகிழ்திறன், சேவை நோக்கம் மற்றும் மிகவும் போட்டி மனப்பான்மை உள்ளவர். இது சக்திவாய்ந்த விபரீத ராஜ யோகத்தை உருவாக்கலாம்.',te:'రిపేశుడు తన స్వంత భావంలో ఉండటం శత్రువులను ఓడించడానికి, న్యాయ పోరాటాలలో గెలవడానికి మరియు వ్యాధులను అధిగమించడానికి శక్తివంతం. జాతకుడు దృఢమైనవాడు, సేవాభిముఖుడు మరియు అత్యంత పోటీతత్వం కలిగినవాడు. ఇది శక్తివంతమైన విపరీత రాజ యోగాన్ని ఏర్పరచవచ్చు.',bn:'রিপেশ নিজ ভাবে থাকা শত্রু পরাজিত করা, আইনি লড়াই জেতা ও রোগ অতিক্রম করার জন্য শক্তিশালী। জাতক স্থিতিস্থাপক, সেবামুখী ও অত্যন্ত প্রতিযোগিতাপ্রবণ। এটি শক্তিশালী বিপরীত রাজ যোগ সৃষ্টি করতে পারে।',mr:'रिपेश स्वतःच्या भावात असणे शत्रूंना पराभूत करण्यास, कायदेशीर लढाया जिंकण्यास व रोगांवर मात करण्यास शक्तिशाली आहे. जातक लवचिक, सेवाभिमुख व अत्यंत स्पर्धात्मक असतो. यामुळे शक्तिशाली विपरीत राज योग बनू शकतो.',pa:'ਰਿਪੇਸ਼ ਆਪਣੇ ਭਾਵ ਵਿੱਚ ਹੋਣਾ ਦੁਸ਼ਮਣਾਂ ਨੂੰ ਹਰਾਉਣ, ਕਾਨੂੰਨੀ ਲੜਾਈਆਂ ਜਿੱਤਣ ਅਤੇ ਰੋਗਾਂ ਤੇ ਕਾਬੂ ਪਾਉਣ ਲਈ ਸ਼ਕਤੀਸ਼ਾਲੀ ਹੈ। ਜਾਤਕ ਲਚਕਦਾਰ, ਸੇਵਾ-ਮੁਖੀ ਅਤੇ ਬਹੁਤ ਮੁਕਾਬਲੇ ਵਾਲਾ ਹੁੰਦਾ ਹੈ। ਇਹ ਸ਼ਕਤੀਸ਼ਾਲੀ ਵਿਪਰੀਤ ਰਾਜ ਯੋਗ ਬਣਾ ਸਕਦਾ ਹੈ।',gu:'રિપેશ પોતાના ભાવમાં હોવું શત્રુઓને હરાવવા, કાનૂની લડાઈઓ જીતવા અને રોગો પર કાબૂ મેળવવા શક્તિશાળી છે. જાતક સ્થિતિસ્થાપક, સેવાલક્ષી અને અત્યંત સ્પર્ધાત્મક હોય છે. આ શક્તિશાળી વિપરીત રાજ યોગ બનાવી શકે.'},
    7:{ta:'ரிபேஷ் ஏழாம் பாவத்தில் இருந்தால் திருமணத்தில் மோதல்கள், துணையுடன் தகராறுகள் மற்றும் வாழ்க்கைத்துணையின் ஆரோக்கிய பிரச்சினைகளை உருவாக்குகிறது. வணிக கூட்டாண்மைகள் தொடர்பான சட்டப் போராட்டங்கள் பொதுவானவை. வாழ்க்கைத்துணை சேவை நோக்கம் அல்லது மருத்துவத் தொழிலராக இருக்கலாம்.',te:'రిపేశుడు ఏడవ భావంలో ఉంటే వివాహంలో ఘర్షణలు, భాగస్వాములతో వివాదాలు మరియు జీవిత భాగస్వామి ఆరోగ్య సమస్యలను సృష్టిస్తుంది. వ్యాపార భాగస్వామ్యాలకు సంబంధించిన న్యాయ పోరాటాలు సాధారణం. జీవిత భాగస్వామి సేవాభిముఖుడు లేదా వైద్య వృత్తినిపుణుడు కావచ్చు.',bn:'রিপেশ সপ্তম ভাবে থাকলে বিবাহে দ্বন্দ্ব, সঙ্গীর সাথে বিরোধ ও জীবনসঙ্গীর স্বাস্থ্য সমস্যা সৃষ্টি করে। ব্যবসায়িক অংশীদারিত্ব সংক্রান্ত আইনি লড়াই সাধারণ। জীবনসঙ্গী সেবামুখী বা চিকিৎসা পেশাজীবী হতে পারে।',mr:'रिपेश सातव्या भावात असल्यास विवाहात संघर्ष, जोडीदाराशी वाद व जोडीदाराच्या आरोग्य समस्या निर्माण करते. व्यावसायिक भागीदारीशी संबंधित कायदेशीर लढाया सामान्य. जोडीदार सेवाभिमुख किंवा वैद्यकीय व्यावसायिक असू शकतो.',pa:'ਰਿਪੇਸ਼ ਸੱਤਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਵਿਆਹ ਵਿੱਚ ਟਕਰਾਅ, ਸਾਥੀ ਨਾਲ ਝਗੜੇ ਅਤੇ ਜੀਵਨ ਸਾਥੀ ਦੀਆਂ ਸਿਹਤ ਸਮੱਸਿਆਵਾਂ ਪੈਦਾ ਕਰਦਾ ਹੈ। ਵਪਾਰਕ ਭਾਈਵਾਲੀਆਂ ਸੰਬੰਧੀ ਕਾਨੂੰਨੀ ਲੜਾਈਆਂ ਆਮ। ਜੀਵਨ ਸਾਥੀ ਸੇਵਾ-ਮੁਖੀ ਜਾਂ ਡਾਕਟਰੀ ਪੇਸ਼ੇਵਰ ਹੋ ਸਕਦਾ ਹੈ।',gu:'રિપેશ સાતમા ભાવમાં હોય તો લગ્નમાં સંઘર્ષ, સાથી સાથે વિવાદ અને જીવનસાથીની આરોગ્ય સમસ્યાઓ સર્જે છે. વ્યાવસાયિક ભાગીદારી સંબંધિત કાનૂની લડાઈઓ સામાન્ય. જીવનસાથી સેવાલક્ષી કે તબીબી વ્યાવસાયિક હોઈ શકે.'},
    8:{ta:'ரிபேஷ் எட்டாம் பாவத்தில் இருந்தால் (துஸ்தானத்திலிருந்து துஸ்தானம்) விபரீத ராஜ யோகத்தை உருவாக்கி, பெரும் இடர்ப்பாட்டிற்குப் பிறகு ஜாதகர் உயர்கிறார். ஜாதகர் நாள்பட்ட நோய்களை வென்று, மாற்றத்தின் மூலம் மறைவான எதிரிகளை தோற்கடிக்கிறார்.',te:'రిపేశుడు ఎనిమిదవ భావంలో ఉంటే (దుస్థానం నుండి దుస్థానం) విపరీత రాజ యోగం ఏర్పడి, గొప్ప ప్రతికూలత తర్వాత జాతకుడు ఎదుగుతాడు. జాతకుడు దీర్ఘకాలిక వ్యాధులను అధిగమించి, పరివర్తన ద్వారా గుప్త శత్రువులను ఓడిస్తాడు.',bn:'রিপেশ অষ্টম ভাবে থাকলে (দুঃস্থান থেকে দুঃস্থান) বিপরীত রাজ যোগ সৃষ্টি হয়, যাতে জাতক মহা প্রতিকূলতার পর উঠে দাঁড়ায়। জাতক দীর্ঘস্থায়ী রোগ অতিক্রম করে ও রূপান্তরের মাধ্যমে গুপ্ত শত্রু পরাজিত করে।',mr:'रिपेश आठव्या भावात असल्यास (दुःस्थानातून दुःस्थान) विपरीत राज योग बनतो, ज्यामुळे जातक मोठ्या प्रतिकूलतेनंतर उभा राहतो. जातक दीर्घकालीन रोगांवर मात करतो व परिवर्तनातून गुप्त शत्रूंना पराभूत करतो.',pa:'ਰਿਪੇਸ਼ ਅੱਠਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ (ਦੁਸਥਾਨ ਤੋਂ ਦੁਸਥਾਨ) ਵਿਪਰੀਤ ਰਾਜ ਯੋਗ ਬਣਦਾ ਹੈ, ਜਿਸ ਨਾਲ ਜਾਤਕ ਵੱਡੀ ਮੁਸ਼ਕਲ ਤੋਂ ਬਾਅਦ ਉੱਠਦਾ ਹੈ। ਜਾਤਕ ਪੁਰਾਣੇ ਰੋਗਾਂ ਤੇ ਕਾਬੂ ਪਾ ਕੇ ਪਰਿਵਰਤਨ ਰਾਹੀਂ ਗੁਪਤ ਦੁਸ਼ਮਣਾਂ ਨੂੰ ਹਰਾਉਂਦਾ ਹੈ।',gu:'રિપેશ આઠમા ભાવમાં હોય તો (દુઃસ્થાનથી દુઃસ્થાન) વિપરીત રાજ યોગ બને છે, જેથી જાતક મોટી પ્રતિકૂળતા પછી ઊભો થાય છે. જાતક દીર્ઘકાલીન રોગો પર કાબૂ મેળવી પરિવર્તન દ્વારા ગુપ્ત શત્રુઓને હરાવે છે.'},
    9:{ta:'ரிபேஷ் ஒன்பதாம் பாவத்தில் இருந்தால் தர்மத்திற்கும் தினசரி கடமைகளுக்கும் இடையே மோதல் ஏற்படுகிறது. ஜாதகர் தந்தை, குருக்கள் அல்லது மத நிறுவனங்களுடன் சட்டப் பிரச்சினைகளை எதிர்கொள்ளலாம். வெளிநாட்டில் ஆன்மிக அல்லது சிகிச்சைத் தொழில்களில் சேவை சாத்தியம்.',te:'రిపేశుడు తొమ్మిదవ భావంలో ఉంటే ధర్మం మరియు దైనందిన కర్తవ్యాల మధ్య ఘర్షణ ఏర్పడుతుంది. జాతకుడు తండ్రి, గురువులు లేదా మత సంస్థలతో న్యాయ సమస్యలను ఎదుర్కోవచ్చు. విదేశాలలో ఆధ్యాత్మిక లేదా వైద్య వృత్తులలో సేవ సాధ్యం.',bn:'রিপেশ নবম ভাবে থাকলে ধর্ম ও দৈনন্দিন কর্তব্যের মধ্যে দ্বন্দ্ব সৃষ্টি হয়। জাতক পিতা, গুরু বা ধর্মীয় প্রতিষ্ঠানের সাথে আইনি সমস্যার সম্মুখীন হতে পারে। বিদেশে আধ্যাত্মিক বা নিরাময় পেশায় সেবা সম্ভব।',mr:'रिपेश नवव्या भावात असल्यास धर्म व दैनंदिन कर्तव्यांत संघर्ष होतो. जातक वडील, गुरू किंवा धार्मिक संस्थांशी कायदेशीर समस्यांना सामोरा जाऊ शकतो. परदेशात आध्यात्मिक किंवा उपचार व्यवसायांत सेवा शक्य.',pa:'ਰਿਪੇਸ਼ ਨੌਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਧਰਮ ਅਤੇ ਰੋਜ਼ਾਨਾ ਕਰਤੱਵਾਂ ਵਿਚਕਾਰ ਟਕਰਾਅ ਹੁੰਦਾ ਹੈ। ਜਾਤਕ ਪਿਤਾ, ਗੁਰੂਆਂ ਜਾਂ ਧਾਰਮਿਕ ਸੰਸਥਾਵਾਂ ਨਾਲ ਕਾਨੂੰਨੀ ਸਮੱਸਿਆਵਾਂ ਦਾ ਸਾਹਮਣਾ ਕਰ ਸਕਦਾ ਹੈ। ਵਿਦੇਸ਼ ਵਿੱਚ ਅਧਿਆਤਮਕ ਜਾਂ ਇਲਾਜ ਪੇਸ਼ਿਆਂ ਵਿੱਚ ਸੇਵਾ ਸੰਭਵ।',gu:'રિપેશ નવમા ભાવમાં હોય તો ધર્મ અને દૈનિક કર્તવ્યો વચ્ચે સંઘર્ષ થાય છે. જાતક પિતા, ગુરુ કે ધાર્મિક સંસ્થાઓ સાથે કાનૂની સમસ્યાઓનો સામનો કરી શકે. વિદેશમાં આધ્યાત્મિક કે ઉપચાર વ્યવસાયોમાં સેવા શક્ય.'},
    10:{ta:'ரிபேஷ் பத்தாம் பாவத்தில் இருந்தால் சேவை, மருத்துவம், ராணுவம், சட்ட அமலாக்கம் அல்லது மோதல் தீர்வில் தொழில் அமைகிறது. ஜாதகர் விடாமுயற்சி உள்ளவர், கடின உழைப்பு மற்றும் போட்டியை வென்று தொழிலில் உயர்கிறார்.',te:'రిపేశుడు పదవ భావంలో ఉంటే సేవ, వైద్యం, సైన్యం, చట్ట అమలు లేదా ఘర్షణ పరిష్కారంలో వృత్తి ఏర్పడుతుంది. జాతకుడు శ్రద్ధగలవాడు, కష్టపడి పని చేయడం మరియు పోటీని అధిగమించడం ద్వారా వృత్తిలో ఎదుగుతాడు.',bn:'রিপেশ দশম ভাবে থাকলে সেবা, চিকিৎসা, সামরিক, আইন প্রয়োগ বা দ্বন্দ্ব নিরসনে কর্মজীবন গড়ে। জাতক পরিশ্রমী, কঠোর পরিশ্রম ও প্রতিযোগিতা অতিক্রম করে কর্মজীবনে উঠে আসে।',mr:'रिपेश दहाव्या भावात असल्यास सेवा, वैद्यक, सैन्य, कायदा अंमलबजावणी किंवा संघर्ष निराकरणात करिअर घडते. जातक परिश्रमी असून कठोर परिश्रम व स्पर्धेवर मात करून करिअरमध्ये उठतो.',pa:'ਰਿਪੇਸ਼ ਦਸਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਸੇਵਾ, ਦਵਾਈ, ਫੌਜ, ਕਾਨੂੰਨ ਲਾਗੂ ਜਾਂ ਟਕਰਾਅ ਹੱਲ ਵਿੱਚ ਕਰੀਅਰ ਬਣਦਾ ਹੈ। ਜਾਤਕ ਮਿਹਨਤੀ ਹੋ ਕੇ ਸਖ਼ਤ ਮਿਹਨਤ ਅਤੇ ਮੁਕਾਬਲੇ ਤੇ ਕਾਬੂ ਪਾ ਕੇ ਕਰੀਅਰ ਵਿੱਚ ਉੱਠਦਾ ਹੈ।',gu:'રિપેશ દશમા ભાવમાં હોય તો સેવા, દવા, સૈન્ય, કાયદા અમલ કે સંઘર્ષ ઉકેલમાં કારકિર્દી બને છે. જાતક ખંતીલો હોઈ સખત મહેનત અને સ્પર્ધા પર કાબૂ મેળવી કારકિર્દીમાં ઊંચે આવે છે.'},
    11:{ta:'ரிபேஷ் பதினொன்றாம் பாவத்தில் இருந்தால் சேவை, சுகாதாரம் அல்லது சட்டப் பணி மூலம் லாபங்கள் வருகின்றன. எதிரிகளிடமிருந்து (அவர்களை வென்று) அல்லது போட்டிக் குழுக்களில் பணிபுரிந்து வருமானம் சாத்தியம். நட்பில் போட்டியாளர்கள் இருக்கலாம்.',te:'రిపేశుడు పదకొండవ భావంలో ఉంటే సేవ, ఆరోగ్య సంరక్షణ లేదా న్యాయ పని ద్వారా లాభాలు వస్తాయి. శత్రువుల నుండి (వారిని ఓడించి) లేదా పోటీ సమూహాలలో పని చేయడం ద్వారా ఆదాయం సాధ్యం. స్నేహాలలో ప్రత్యర్థులు ఉండవచ్చు.',bn:'রিপেশ একাদশ ভাবে থাকলে সেবা, স্বাস্থ্যসেবা বা আইনি কাজের মাধ্যমে লাভ আসে। শত্রুর কাছ থেকে (তাদের হারিয়ে) বা প্রতিযোগিতামূলক দলে কাজ করে আয় সম্ভব। বন্ধুত্বে প্রতিদ্বন্দ্বী থাকতে পারে।',mr:'रिपेश अकराव्या भावात असल्यास सेवा, आरोग्यसेवा किंवा कायदेशीर कामातून लाभ येतात. शत्रूंकडून (त्यांना हरवून) किंवा स्पर्धात्मक गटांत काम करून उत्पन्न शक्य. मैत्रीत प्रतिस्पर्धी असू शकतात.',pa:'ਰਿਪੇਸ਼ ਗਿਆਰਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ ਸੇਵਾ, ਸਿਹਤ ਸੇਵਾ ਜਾਂ ਕਾਨੂੰਨੀ ਕੰਮ ਰਾਹੀਂ ਲਾਭ ਆਉਂਦੇ ਹਨ। ਦੁਸ਼ਮਣਾਂ ਤੋਂ (ਉਹਨਾਂ ਨੂੰ ਹਰਾ ਕੇ) ਜਾਂ ਮੁਕਾਬਲੇ ਵਾਲੇ ਸਮੂਹਾਂ ਵਿੱਚ ਕੰਮ ਕਰਕੇ ਆਮਦਨ ਸੰਭਵ। ਦੋਸਤੀ ਵਿੱਚ ਵਿਰੋਧੀ ਹੋ ਸਕਦੇ ਹਨ।',gu:'રિપેશ અગિયારમા ભાવમાં હોય તો સેવા, આરોગ્યસેવા કે કાનૂની કામ દ્વારા લાભ આવે છે. શત્રુઓથી (તેમને હરાવીને) કે સ્પર્ધાત્મક જૂથોમાં કામ કરીને આવક શક્ય. મિત્રતામાં હરીફો હોઈ શકે.'},
    12:{ta:'ரிபேஷ் பன்னிரண்டாம் பாவத்தில் இருந்தால் (துஸ்தானத்திலிருந்து துஸ்தானம்) மற்றொரு விபரீத ராஜ யோகம் உருவாகிறது. எதிரிகள் ஒருவரையொருவர் அழிக்கிறார்கள், கடன்கள் தீர்க்கப்படுகின்றன, ஆரோக்கிய பிரச்சினைகள் காலப்போக்கில் தீர்கின்றன. ஜாதகர் அனைத்து எதிரிகளையும் வெல்கிறார்.',te:'రిపేశుడు పన్నెండవ భావంలో ఉంటే (దుస్థానం నుండి దుస్థానం) మరో విపరీత రాజ యోగం ఏర్పడుతుంది. శత్రువులు ఒకరినొకరు నాశనం చేసుకుంటారు, అప్పులు తీరుతాయి, ఆరోగ్య సమస్యలు కాలక్రమేణా పరిష్కారమవుతాయి. జాతకుడు అందరు ప్రత్యర్థులపై విజయం సాధిస్తాడు.',bn:'রিপেশ দ্বাদশ ভাবে থাকলে (দুঃস্থান থেকে দুঃস্থান) আরেকটি বিপরীত রাজ যোগ সৃষ্টি হয়। শত্রুরা পরস্পরকে ধ্বংস করে, ঋণ পরিশোধ হয় ও স্বাস্থ্য সমস্যা সময়ের সাথে সমাধান হয়। জাতক সব প্রতিদ্বন্দ্বীর ওপর বিজয়ী হয়।',mr:'रिपेश बाराव्या भावात असल्यास (दुःस्थानातून दुःस्थान) आणखी एक विपरीत राज योग बनतो. शत्रू एकमेकांना नष्ट करतात, कर्ज फेडली जातात व आरोग्य समस्या काळानुसार सुटतात. जातक सर्व प्रतिस्पर्ध्यांवर विजय मिळवतो.',pa:'ਰਿਪੇਸ਼ ਬਾਰ੍ਹਵੇਂ ਭਾਵ ਵਿੱਚ ਹੋਵੇ ਤਾਂ (ਦੁਸਥਾਨ ਤੋਂ ਦੁਸਥਾਨ) ਇੱਕ ਹੋਰ ਵਿਪਰੀਤ ਰਾਜ ਯੋਗ ਬਣਦਾ ਹੈ। ਦੁਸ਼ਮਣ ਇੱਕ-ਦੂਜੇ ਨੂੰ ਨਸ਼ਟ ਕਰਦੇ ਹਨ, ਕਰਜ਼ ਚੁਕਾਏ ਜਾਂਦੇ ਹਨ ਅਤੇ ਸਿਹਤ ਸਮੱਸਿਆਵਾਂ ਸਮੇਂ ਨਾਲ ਹੱਲ ਹੁੰਦੀਆਂ ਹਨ। ਜਾਤਕ ਸਾਰੇ ਵਿਰੋਧੀਆਂ ਤੇ ਜਿੱਤ ਪ੍ਰਾਪਤ ਕਰਦਾ ਹੈ।',gu:'રિપેશ બારમા ભાવમાં હોય તો (દુઃસ્થાનથી દુઃસ્થાન) બીજો વિપરીત રાજ યોગ બને છે. શત્રુઓ એકબીજાને નષ્ટ કરે છે, દેવું ચૂકવાય છે અને આરોગ્ય સમસ્યાઓ સમય સાથે ઉકેલાય છે. જાતક બધા હરીફો પર વિજય મેળવે છે.'},
  },
};

exports.seed = async function (knex) {
  for (const [houseLord, langs] of Object.entries(LORD_META)) {
    const update = {};
    for (const [lang, f] of Object.entries(langs)) {
      update[`lord_name_${lang}`] = f.name;
      update[`house_signification_${lang}`] = f.sig;
    }
    await knex('house_lord_interpretations').where({ house_lord: Number(houseLord) }).update(update);
  }
  for (const [houseLord, houses] of Object.entries(INTERP)) {
    for (const [placedIn, langs] of Object.entries(houses)) {
      const update = {};
      for (const [lang, txt] of Object.entries(langs)) update[`interpretation_${lang}`] = txt;
      await knex('house_lord_interpretations')
        .where({ house_lord: Number(houseLord), placed_in_house: Number(placedIn) })
        .update(update);
    }
  }
};
